INSERT INTO `favorites` (`user_id`, `id`, `is_tv`, `title`, `poster_path`, `backdrop_path`, `overview`, `vote_average`, `release_date`, `genre_ids`, `created_at`, `updated_at`, `deleted`) VALUES
(2, 101, 0, 'Leon: Sevginin Gücü', '/5wc5a1z0POdwMfDVrjbeTEhfygV.jpg', '/fj0hwDJEOOHllRim2BMt5L7tbjf.jpg', 'Mathilda, New York’ta yaşayan ailesi dağılmış 12 yaşında küçük bir kızdır. Ailesini sevmeyen Mathilda için en değerli varlığı küçük kardeşidir. Babası uyuşturucu işlerine bulaşınca mafya ailenin tüm bireylerini öldürür. O sırada alışverişte olan Mathilda ise olaydan kılpayı kurtulur ve Leon’un kaldığı daireye saklanır. Leon ise çok soğukkanlı bir katildir. Ancak Mathilda’ya karşı içten bir sevgi besler ve ona kol kanat gerer. Aslında babalık, arkadaşlık gibi kavramlar ona çok yabancıdır.', 8.294, '1994-09-14', '[80,18,28]', 0, 1783264868402, 1),
(2, 194, 0, 'Amelie', '/d6aA2hQmrUN1pGzioXldstNelur.jpg', '/6n53UI4mX9QMfe2S0Pgt8mGebY1.jpg', 'Paris\'te garsonluk yaparak, kendine özgü bir dünyada yaşayan saf, çekingen ve masum bir kızdır Amelie. Annesinin beklenmedik ölümü, babasının soğuk tavırları ve yaşadığı travmalar sonucu, sevimli ve boş şeylerle uğraşarak kendisine eğlence yaratmaya çalışsa da aslında hayatı sıkıcı bulduğu için kendisini son derece yalnız hissetmektedir. Bu kısır döngü Amelie’nin evde bulduğu bir kutuyu ve onun aracılığıyla sahibini keşfetmesiyle birlikte bir anda bıçak gibi kesiliverir... Amelie aşık olmuştur.', 7.919, '2001-04-25', '[35,10749]', 1, 1783264868402, 1),
(2, 1399, 1, 'Game of Thrones', '/1XS1oqL89opfnbLl8WnZY1O1uJx.jpg', '/2OMB0ynKlyIenMJWI2Dy9IWT4c.jpg', 'Krallık dediğin savaşsız olur mu? En güçlü krallığı kurup huzuru sağlamış olsanız bile bu gücü elinizde nasıl tutardınız? Burada yanlış yapana yer yok, affetmek yok. Hanedan entrikaları, kapılı kapılar ardında dönen oyunlar, birilerinin kuyusunu kazmak için düşmanın koynuna girmekten çekinmeyen kadınlar, kardeşler arası çekişmeler, dışlanmalar. Hepsi tek bir amaç için: taht kavgası.', 8.5, '2011-04-17', '[10765,18,10759]', 0, 1783264868402, 1),
(2, 1579, 0, 'Apocalypto', '/cRY25Q32kDNPFDkFkxAs6bgCq3L.jpg', '/nnmbJvYyDS1VkMOCbxSpdBi3WbJ.jpg', 'Güçlü Maya Krallığı, gittikçe yayılan şehirler kurarak, gökyüzünü delen piramitler yaparak ve olağanüstü kültürel ve bilimsel başarılar elde eden etkileyici gelişmiş bir toplum inşa ederek Amerika’da 1000 yıldan fazla bir süre hüküm sürdü. Ondan sonra, tarihin ışıltısı içinde, bu dünya çöktü. Bütün bunlardan geriye kalan ormanlarla kaplı birkaç piramit ve boşuna umut veren bir gizem oldu. Şimdi, Maya uygarlığının sona ermesinden 500 sene sonra, yönetmen Mel Gibson, felaketin kıyısındaki bir dünyada kendisi için en fazla önem taşıyan şey olan ülkeyi kurtaracak olan bir adamın macerası üzerine kurulan belirli bir zamanı olmayan bir efsanede olduğu gibi her şeyi gözler önüne seren modern bir film macerası yaratmak için asla keşfedilmemiş bu ülkeyi derinlemesine araştırıyor.', 7.645, '2006-12-07', '[28,18,36]', 2, 1783264868402, 1),
(2, 14784, 0, 'Düşüş', '/cQ9W5vWeBiDQP89qmvrqUQPTChT.jpg', '/vNrXoT45xscHY6AN4IGf44vHxVJ.jpg', 'Video klip ve reklamların usta yönetmeni Singh\'in odağında bu kez, sakat bir adam ile küçük bir kızın bir hastanede yaşadıkları olağandışı aşk hikâyesi var. Adam ve kız kendi aralarında, intikam peşindeki beş kahraman hakkında bir masal uydururlar: Maskeli bir kabadayı, Afrikalı kaçak bir köle, Hintli bir mistik, İtalyan bir anarşist ve bir doğabilimci, ıssız bir adaya sürgün edilmişlerdir. Düşüş, akıl almaz sahnelerin rengârenk canlandırma planlarıyla harmanlandığı son dönem filmler arasında, izleyiciyi görselliğiyle yakalayacak, akıllardan kolay silinmeyecek bir yapıt.', 7.625, '2006-09-09', '[12,14,18]', 1, 1783112757099, 1),
(2, 44217, 1, 'Vikingler', '/qkCh6cFSHikSIFTWUQyJ2qJzqsy.jpg', '/13kblIK8DnxMurcRDkeyy2sGR7v.jpg', 'Viking kahramanı Ragnar Lothbrok’un, ileriyi göremeyen, yetersiz bir lidere meydan okuyarak Norse sınırlarını nasıl genişlettiğini seyrettiğimiz gerçekçi bir dram.', 8.096, '2013-03-03', '[10759,18,10768]', 2, 1783264868402, 1),
(2, 46296, 1, 'Spartacus', '/c2GKN4VHCj1dnjFMANRpGkCVBae.jpg', '/zbfXS4o6UykeXsD8djFTyV7Cj4N.jpg', 'Trakyalı bir asker olan Spartacus sürekli baskısı altında kaldıkları Roma Cumhuriyeti ile birlikte Getaelar\'a karşı savaşmak için Roma ordusuna katılır. İlk çarpışmadan sonra Spartacus doğuya doğru çekilen Getae ordusunu takip etmek yerine Karadeniz\'e gitme emri veren Gaius Claudius Glaber\'a karşı gelir ve köyüne gitmeye karar verir. Köyüne yaklaştığında Getaelar\'ın orayı mahvettiğini görür ancak karısı kurtulmuştur. Geceyi bir mağarada karısıyla geçiren Spartacus\'u sabah Roma ordusu bulur. Glaber, Spartacus\'u köle olarak alır ve karısını da Suriyeli bir tüccara satar. Spartacus daha sonra Ludus\'a girer ve karısını bulmak için savaşmaya başlar.', 8.028, '2010-01-22', '[18]', 1, 1783264868402, 1),
(2, 1039764, 0, '生きる', '/gIZUUOsVkJ95CWv3N6uXWnuCRUO.jpg', NULL, '', 0, '2007-09-09', '[10770,18]', 2, 1783112757099, 1),
(4, 101, 0, 'Leon: Sevginin Gücü', '/5wc5a1z0POdwMfDVrjbeTEhfygV.jpg', '/fj0hwDJEOOHllRim2BMt5L7tbjf.jpg', 'Mathilda, New York’ta yaşayan ailesi dağılmış 12 yaşında küçük bir kızdır. Ailesini sevmeyen Mathilda için en değerli varlığı küçük kardeşidir. Babası uyuşturucu işlerine bulaşınca mafya ailenin tüm bireylerini öldürür. O sırada alışverişte olan Mathilda ise olaydan kılpayı kurtulur ve Leon’un kaldığı daireye saklanır. Leon ise çok soğukkanlı bir katildir. Ancak Mathilda’ya karşı içten bir sevgi besler ve ona kol kanat gerer. Aslında babalık, arkadaşlık gibi kavramlar ona çok yabancıdır.', 8.294, '1994-09-14', '[80,18,28]', 2, 1782998735198, 0),
(4, 122, 0, 'Yüzüklerin Efendisi: Kralın Dönüşü', '/qwigzi0gOcXZRxbm488wT31t2UZ.jpg', '/2u7zbn8EudG6kLlBzUYqP8RyFU4.jpg', 'Karanlığın bütün güçleri son savaş için bir araya gelirken Gandalf, Gondor\'un yaralı ordusunu toparlamak için hazırlıklara başlar. Thoden, tarihin bu en büyük savaşı için tüm savaşçılarını seferber eder. İçlerinde saklanan Eowyn ve Merry ile birlikte insanlar, tüm cesaretlerine rağmen Gondor\'u kuşatan düşmanlar karşısında güçsüzdür. Yinede Yüzük Taşıyıcısı\'nın yolculuğunu tamamlamasini için hayatlarının en zor savaşında birbirlerine kenetlenirler.', 8.499, '2003-12-17', '[12,14,28]', 1, 1782998735198, 0),
(4, 2062, 0, 'Ratatuy', '/a7hjVvftDqdgqZidGyoDkpXWjtK.jpg', '/xgDj56UWyeWQcxQ44f5A3RTWuSs.jpg', 'Şişman fare Remy, yemeğe olan düşkünlüğü nedeniyle tek bir hayale sahiptir: Aşçı olabilmek! Bu idealini gerçekleştirmek için Paris\'in yolunu tutan sevimli fare kaza eseri kendisini şehrin en iyi restoranının kanalizasyonunda bulur. Restoranın yeni çöpçüsüyle ilginç bir anlaşma yapan Remy, tüm hünerlerini sergileyebileceği büyülü mutfağa ulaşmIştır. Ancak bu tek hayalini gerçekleştirmek, farelerden iğrenen bir insanlığın var olduğu bir dünyada pek kolay olmayacaktır.', 7.843, '2007-06-28', '[16,35,10751,14]', 2, 1782998735198, 1),
(4, 14784, 0, 'Düşüş', '/cQ9W5vWeBiDQP89qmvrqUQPTChT.jpg', '/vNrXoT45xscHY6AN4IGf44vHxVJ.jpg', 'Video klip ve reklamların usta yönetmeni Singh\'in odağında bu kez, sakat bir adam ile küçük bir kızın bir hastanede yaşadıkları olağandışı aşk hikâyesi var. Adam ve kız kendi aralarında, intikam peşindeki beş kahraman hakkında bir masal uydururlar: Maskeli bir kabadayı, Afrikalı kaçak bir köle, Hintli bir mistik, İtalyan bir anarşist ve bir doğabilimci, ıssız bir adaya sürgün edilmişlerdir. Düşüş, akıl almaz sahnelerin rengârenk canlandırma planlarıyla harmanlandığı son dönem filmler arasında, izleyiciyi görselliğiyle yakalayacak, akıllardan kolay silinmeyecek bir yapıt.', 7.625, '2006-09-09', '[12,14,18]', 0, 1782998735198, 0),
(4, 19885, 1, 'Sherlock', '/7WTsnHkbA0FaG6R9twfFde0I9hl.jpg', '/8rvLEmdI4gLrMO1rLqbNdnNcPFE.jpg', 'Arthur Conan Doyle\'un ünlü eserinden uyarlanan yapımda, kahramanlarımız Sherlock Holmes ve Dr. John Watson günümüz Londra\'sında sıradışı cinayetleri çözmeye çalışıyorlar. Huysuz Sherlock ile insancıl John, maceradan maceraya atılırken, izleyici kendisini aksiyondan komediye uzanan bir koşuşturmacanın içinde buluyor. ', 8.506, '2010-07-25', '[80,18,9648]', 0, 1782998786524, 0),
(5, 37181, 0, 'Elly Hakkında', '/c97J9uHN1S9kFaEK4rSGVgCFBcG.jpg', '/3loY85G8vB0OcpleFFezf4kSDsy.jpg', 'Almanya’da yaşayan Ahmad, bir süre sonra İran’ı ziyarete gider. Orada onu eski arkadaşları karşılayacaklardır. Birlikte bir tatil planı yaparlar. Hazar Gölü kıyısında üç gün birlikte eğleneceklerdir. Tatili düzenleyen Sepideh, bu tatile Elly’ı da çağırır. Ahmad, Elly’ı tanımamaktadır ama Sepideh’in amacı biraz da onları yakınlaştırmaktır. Tatil güzel geçmektedir ta ki ikinci gün Elly kaybolana dek. O günün sabahında Tahran’a dönmesi gerektiğini söylemiş olan Elly nasıl yok olmuştur? Bu andan itibaren bazı yalanlar ortaya çıkar ve yalanın tüm olayların seyrini nasıl değiştirebildiği gözler önüne serilir.', 7.469, '2009-06-06', '[18]', 1, 1783010325499, 0),
(5, 381283, 0, 'anne!', '/r7nGgMOwEI3SIsjN0UMy4fDNmgo.jpg', '/2wS8pMZgvzq7kaZb5LHX54poQnA.jpg', 'Film, düzenlerini bozma ihtimaline karşı hayatlarına kimseyi dahil etmeyen, misafir bile kabul etmeyen bir çifti konu almaktadır. Bir gün davetsiz misafirler evlerine geldiğinde, çiftimizin sakin hayatları beklenmedik şekilde bozulacak ve gizlenen amaçların ne olduğu sorgulanmaya başlanacaktır.', 6.959, '2017-09-13', '[27,18]', 0, 1783010325499, 0),
(5, 620350, 0, 'National Theatre Live: Fleabag', '/ym3Jo2mo2dK9Z27ryMr5mmkDljx.jpg', '/h3StNE0j4jc1qFt88t7IR2w4wVm.jpg', '', 7.7, '2019-09-12', '[35,18]', 2, 1783010325499, 0);
