INSERT INTO `ratings` (`user_id`, `movie_id`, `is_tv`, `rating`, `genre_ids`, `title`, `poster_path`, `backdrop_path`, `overview`, `vote_average`, `release_date`, `popularity`, `created_at`, `updated_at`, `deleted`, `comment`, `is_spoiler`) VALUES
(2, 24, 0, 2, '[28,80]', 'Kill Bill: Vol. 1', '/v7TaX8kXMXs5yFFGR41guUDNcnB.jpg', '/iffzIhuLAO38Po6sh1s6ZEVwlNL.jpg', 'Sıra dışı yazar ve yönetmen Quentin Tarantino\'nun büyük beğeni kazanan dördüncü filmi olan, acımasız bir ihaneti ve destansı bir kan davasını konu alan heyecan ve gerilimi yüksek Kill Bill: Volume 1\'de başrollerde Uma Thurman (Pulp Fiction), Lucy Liu (Charlie\'s Angels, Chicago) ve Vivica A Fox\' u (Two Can Play That Game) izleyeceksiniz. Kendi nikah töreninde başına bir kurşun isabet ettikten dört yıl sonra, Gelin (Thurman) komadan çıkar ve intikam alma vakti geldiğine karar verir! Eski patronu Bill (David Carradine) ve onun ölümcül uluslararası suikast ekibi tarafından vurulduğu göz önüne alınırsa artık kendisinin başlatmadığı ancak bitirmeye kararlı olduğu bir ölüm kalım savaşı onu beklemektedir. Tüm dünyada ses getiren aksiyon dolu nükteli bu film, mutlaka görülmesi gereken bir yapım.', 7.973, '2003-10-10', 14.7476, 1783281472237, 1783281472237, 0, '', 0),
(2, 36, 1, -1, '[80,18,9648,10765]', 'Medium', '/6tOxspW2MbbAQ0s3jtfs8QATcx.jpg', '/dVpAGo3TT2IjDyRuKwhNfe9E1A5.jpg', 'Allison Dubois works in the District Attorney’s office using her natural intuition about people and her ability to communicate with the dead to help to solve crimes. Her dreams often give her clues to the whereabouts of missing people.', 7.467, '2005-01-03', 51.1773, 1783320711056, 1783320711056, 0, NULL, 0),
(2, 38, 0, 2, '[878,18,10749]', 'Sil Baştan', '/zZl2T3yj80dwaWBeOWZQoFOJwGe.jpg', '/W1ffLQGHoxfAOq0ZYdPtJlvAdb.jpg', 'Joel Barish, iki yıl boyunca beraber olduğu sevgilisinden oldukça şaşırtıcı bir haber alıyor. Kadın, bir teknolojik deneye katılarak, ilişkilerini tamamen hafızasından silmiştir. Yani Barish\'in kim olduğunu bile hatırlamamaktadır. Bu gelişme üzerine küplere binen adam, aynı prosedürü kendi üzerinde de gerçekleştirmek ister...Film, adamın hafızaları silinirken, yaşanılan ilişkiyi gözler önüne serer. Adam da bir kez daha oldukça iyi başlayan ve sonradan tadı kaçan ilişkiyi izler. Fakat zaman geçtikçe ve sıra yaşanılan güzel şeylere gelince, üzerindeki müdaheleyi durdurmak ister. Pişman olmuştur!', 8.09, '2004-03-19', 18.3959, 1783280624098, 1783280624098, 0, '', 0),
(2, 55, 0, 2, '[18,53]', 'Paramparça Aşklar Köpekler', '/seB5OVzZ0wmNZ7Jk2AzNeWIT7Bu.jpg', '/tJTRLtdKPeVT8HORSbeHpdb8BKg.jpg', 'Octavio, genç bir delikanlıdır, kardeşinin karısı Susana ile kaçmaya karar verir. Köpeği Cofi, beraber kaçmalarına yardımcı olan paranın elde edilmesinde rol oynayan zalim bir aracı olur. Bu dokunaklı ihtiras üçgeni, yasak aşkın geri dönüşü olmayan bir yol haline gelmesiyle daha karmaşık bir hal alır.\r Bu arada Daniel, 42 yaşında bir adamdır, güzel model Valeria ile beraber yaşamak için karısını ve kızlarını terk eder. Yeni hayatlarını kutladıkları gün, kader Valeria’yı trajik bir kazaya iter. Bir adam her şeye sahip olduğunu düşündüğü anda, tüm hayatı birdenbire değişirse ne yapar?\r Daniel ve Valeria’nın küçük köpeği Richi, oturdukları dairenin ahşap zeminindeki boşluğa düşer. Bu olay onların kötü kaderlerinin de başlangıcı olur. Richi’nin kaybolması karşısında takındıkları tutum, her türlü zorluğa ve umutsuzluğa cesurca göğüs gerebilen aşk hikayelerine mükemmel bir örnek teşkil eder...', 7.639, '2000-06-16', 6.351, 1783280904935, 1783280904935, 0, '', 0),
(2, 98, 0, 3, '[28,18,12]', 'Gladyatör', '/kRSCWiRPEVhUIleK1bZKMZ5uZ4p.jpg', '/jhk6D8pim3yaByu1801kMoxXFaX.jpg', 'Roma İmparatorluğu\'na en parlak dönemi yaşatan General Maximus, girdiği bir meydan savaşından daha zaferle çıkar, artık tek hayali bir an önce evine dönerek karısı ve ailesine kavuşmaktır.  Fakat, zamanın Roma İmparatoru Marcus Aurelius, Maximus\'a önemli bir görev verir ve iktidara sahip çıkmasını ister. Bunun üzerine imparatorun oğlu olan Commodus, iktidarın elinden alınacağını anlayınca general ve ailesini öldürme emri verir. Maximus ölümden zor kurtulur ve gladyatörler arenasına sürgün edilir. Yıllar sonra Roma\'ya geri dönen güçlü gladyatör Maximus\'un tek amacı Commodus\'u öldürerek karısı ve oğlunun katledilmesinin intikamını almaktır.', 8.227, '2000-05-04', 28.9113, 1783056386052, 1783264868402, 1, NULL, 0),
(2, 101, 0, 3, '[80,18,28]', 'Leon: Sevginin Gücü', '/5wc5a1z0POdwMfDVrjbeTEhfygV.jpg', '/fj0hwDJEOOHllRim2BMt5L7tbjf.jpg', 'Mathilda, New York’ta yaşayan ailesi dağılmış 12 yaşında küçük bir kızdır. Ailesini sevmeyen Mathilda için en değerli varlığı küçük kardeşidir. Babası uyuşturucu işlerine bulaşınca mafya ailenin tüm bireylerini öldürür. O sırada alışverişte olan Mathilda ise olaydan kılpayı kurtulur ve Leon’un kaldığı daireye saklanır. Leon ise çok soğukkanlı bir katildir. Ancak Mathilda’ya karşı içten bir sevgi besler ve ona kol kanat gerer. Aslında babalık, arkadaşlık gibi kavramlar ona çok yabancıdır.', 8.294, '1994-09-14', 18.1319, 1783018585935, 1783264868402, 1, '', 0),
(2, 111, 0, -1, '[28,80,18]', 'Yaralı Yüz', '/9F7xtVA6cKGdjkVu2s33C09oZAP.jpg', '/1qM2BYNE11Viby8ImC9LC00DgDr.jpg', 'Tony Montana isimli Kübalı suçlu, Miami\'ye gelip uyuşturucu lordu Robert Loggia\'nın emrinde çalışmaya başlar. Montana\'nın hırsı ve öfkesi basamaklaı hızla tırmanıp büyük bir suç şebekesinin başı olmasını sağlar. Film, uyuşturucu dünyasının gizli kapılar ardında dönen çarklarından başlayarak suç dünyasını gözler önüne serer.', 8.155, '1983-12-09', 24.5359, 1783285386786, 1783285386786, 0, NULL, 0),
(2, 155, 0, 2, '[28,80,53]', 'Kara Şövalye', '/7IPCEr7ifdH5CtU97QG7XgAAtOp.jpg', '/cfT29Im5VDvjE0RpyKOSdCKZal7.jpg', 'Batman, Teğmen Jim Gordon ve Bölge Savcısı Harvey Dent’in yardımlarıyla, şehir sokaklarını sarmış olan suç örgütlerinden geriye kalanları temizlemeye girişir. Bu ortaklığın etkili olduğu açıktır, ama ekip kısa süre sonra kendilerini, Joker olarak bilinen ve Gotham şehri sakinlerini daha önce de dehşete boğmuş olan suç dehasının yarattığı karmaşanın ortasında bulurlar.', 8.531, '2008-07-16', 44.9694, 1783056261743, 1783264868402, 1, NULL, 0),
(2, 194, 0, 3, '[35,10749]', 'Amelie', '/d6aA2hQmrUN1pGzioXldstNelur.jpg', '/6n53UI4mX9QMfe2S0Pgt8mGebY1.jpg', 'Paris\'te garsonluk yaparak, kendine özgü bir dünyada yaşayan saf, çekingen ve masum bir kızdır Amelie. Annesinin beklenmedik ölümü, babasının soğuk tavırları ve yaşadığı travmalar sonucu, sevimli ve boş şeylerle uğraşarak kendisine eğlence yaratmaya çalışsa da aslında hayatı sıkıcı bulduğu için kendisini son derece yalnız hissetmektedir. Bu kısır döngü Amelie’nin evde bulduğu bir kutuyu ve onun aracılığıyla sahibini keşfetmesiyle birlikte bir anda bıçak gibi kesiliverir... Amelie aşık olmuştur.', 7.919, '2001-04-25', 13.6057, 1783265220761, 1783265220761, 0, '', 0),
(2, 220, 0, -1, '[18]', 'Cennetin Doğusu', '/xv1MZVIop0SQqwLUymgE5eb2LFl.jpg', '/u7i1XtbOubq0xwRy2Zbgmox6g9W.jpg', 'I.Dünya Savaşı sıralarında, Cal Trask, babasının sevgisini kazanmak için kardeşi Aron\'la yarış halinde.. Ancak Cal, karakteri açısından savaşla, işiyle ve kendisiyle iyi bir ilişkisi olmayan annesiyle devamlı kavga etmeyi yeğliyor. \"Cennetin Doğusu\", ünlü yazar John Steinbeck\'in aynı adlı romanından Elia Kazan tarafından yapılmış bir uyarlama...  Cennetin Doğusu, (East of Eden) yönetmenliğini Elia Kazan\'ın yaptığı, 1955 yapımı bir ABD filmidir. John Steinbeck\'in aynı adlı romanından, Paul Osborn tarafından senaryolaştırıldı. Başlıca rollerini James Dean, Julie Harris ve Raymond Massey\'nin paylaştığı film, Jo Van Fleet\'e En iyi yardımcı kadın oyuncu oscarını kazandırdı. Ayrıca film, en iyi aktör, en iyi yönetmen ve en iyi senaryo oscarlarına da aday gösterildi. Film, Golden Globe, Cannes film festivali gibi birçok törenden ödülle dönmüştür...', 7.5, '1955-04-10', 2.5511, 1783191879024, 1783264868402, 1, NULL, 0),
(2, 238, 0, 2, '[18,80]', 'Baba', '/vseIVRdN4xasYwStQIi6SI7DcEu.jpg', '/tSPT36ZKlP2WVHJLM4cQPLSzv3b.jpg', 'Mario Puzo\'nun çok satan kitabından Puzo ve yönetmen Francis Ford Coppola tarafından sinemaya uyarlanan eser, 40\'lar ve 50\'lerin Amerika\'sında, bir İtalyan mafya ailesinin destansı öyküsünü konu alıyor. Corleone ailesi, Don Vito Corleone\'nin başında olduğu, suça dayalı bir örgüt kurmuş olan İtalyan asıllı meşhur bir ailedir. Aile, New York\'taki diğer dört aileyle birlikte New York\'un yeraltı işlerini yönetmektedir. Ancak Corleone ailesini diğerlerinden ayıran özelliği, Don Corleone\'nin cebinde bozuk para gibi taşıdığı politikacılar ve yargıçlardır. Politikacılar ve yargıçlarla olan bu yakın ilişkileri diğer ailelerin açamadığı kapıları açabilmesini sağlamaktadır.', 8.687, '1972-03-14', 42.0762, 1783271578006, 1783271578006, 0, NULL, 0),
(2, 240, 0, 2, '[18,80]', 'Baba II', '/3Yaj5y25485A2YeixwayoP8ywZ0.jpg', '/kGzFbGhp99zva6oZODW5atUtnqi.jpg', 'Genç Vito Corleone, Amerika\'ya yeni gelmiştir. 1917 yılında, New York şehri\'nin yerel mafyalarından birinin liderini öldürünce saygınlık kazanır ve korkulan biri haline gelir.Bu arada, 50 yıl sonra, Michael Corleone, Washington\'da senato komitesine aile işleriyle ilgili ifade vermektedir.1972 yapımı ilk filmin devamı niteliğinde, yine yazar Mario Puzo ve yönetmen Francis Ford Coppola\'nın yaratıcı ellerinden çıkmış usta işi bir yapım. Eleştirmenler tarafından, önceki filmden daha başarılı bulunan az sayıdaki devam filminden biri olarak kabul ediliyor.', 8.571, '1974-12-20', 28.6034, 1783266545896, 1783266545896, 0, NULL, 0),
(2, 272, 0, -1, '[18,80,28]', 'Batman Başlıyor', '/f1pQPzFmBXyFaScnrqeSm8lvCH9.jpg', '/9IIBboV7MCT0bTxzXHmWK1Hq558.jpg', 'Batman efsanesinin devamı olan Batman Başlıyor\'da Kara Şövalye Gotham şehrinin iyiliği için her şeyi göze alıyor. Anne ile babasının ölümünün ardından hayal kırıklığına uğrayan miras zengini Bruce Wayne (Christian Bale) adaletsizliğe karşı savaşmak ve korkanlardan beslenenleri korkutmak için dünyayı gezer. Gotham\'a geri dönen Wayne, şehri tehdit eden kötü güçlerle gücü, zekası ve bir dizi ileri teknoloji cihazı kullanan maskeli kahraman Batman olarak ortaya çıkar.', 7.728, '2005-06-10', 24.1059, 1783056373765, 1783264868402, 1, NULL, 0),
(2, 274, 0, 2, '[80,53,18]', 'Kuzuların Sessizliği', '/4AoIoP6q006blFeb7vV9kKPD4En.jpg', '/aYcnDyLMnpKce1FOYUpZrXtgUye.jpg', 'Akademiden başarıyla mezun olmuş genç FBI ajanı Clarice Starling, kurbanlarının derilerini yüzen sapık bir katilin elinden bir kadını kurtarmaya çalışır. Clarice, katile ulaşmak için başka bir psikopat olan ünlü doktor Hannibal Lecter ile yakınlaşır. Lecter\'dan bilgi alabilmesi için önce onun güvenini kazanması gerekmektedir.1992 yılında 7 dalda Oscar\'a aday olan film, yönetmeni ve başrol oyuncularına altın heykelciği getirirken en iyi film ve en iyi senaryo uyarlaması dalında da ödüle hak kazanmıştı.', 8.345, '1991-02-14', 6.4122, 1783237460530, 1783241221763, 1, NULL, 0),
(2, 278, 0, 3, '[18,80]', 'Esaretin Bedeli', '/7T2SDS5efuJiK45oyKoEzf9RKjw.jpg', '/zfbjgQE1uSd9wiPTX4VzsLi0rGG.jpg', 'Genç ve başarılı bir banker olan Andy Dufresne, karısını ve onun sevgilisini öldürmek suçundan ömür boyu hapse mahkum edilir ve Shawshank hapishanesine gönderilir. İşkence, tecavüz, dayak dahil her türlü kötü koşulun hüküm sürdüğü hapishane koşullarında, Andy\'nin hayata bağlı ve her daim iyi bir şeyler bulma çabası içindeki hali, çevresindeki herkesi çok etkileyecektir. Bir süre sonra parmaklıkların arkasında bile özgür bir yaşam olabileceğine bütün mahkumları inandırır. Bu mahkumlardan biri olan Ellis Boyd \"Red\" ve Andy, unutulmaz bir dostluk kurarak hapishaneyi bambaşka bir yer haline getirirler.', 8.724, '1994-09-23', 163.6421, 1783272213248, 1783272213248, 0, NULL, 0),
(2, 281, 0, -1, '[80,18,878,53]', 'Tuhaf Günler', '/rY5BrDRcYAKE0BYmmT66YG6Uy5Q.jpg', '/zSFuvi6fIPT8CHpH1KMG25T2Iub.jpg', '1999 yılında‚ yeni milenyuma geçişin arifesinde‚ batı toplumu yarı anarşik kontrolden çıkmış bir hayat yaşamaktadır. Kendi geçmişinin hayaletlerinden kurtulamayan Los Angeleslı genç bir polis eskisi olan Lenny Nero‚ şimdi artık kısaca klip denilen‚ başkalarının yaşadığı anıların satıldığı karaborsanın simsarlarından biridir. Kaybettiği eski kız arkadaşı Faith ile olan kendi kliplerinin de bağımlısıdır. Los Angeles polisinden iki dedektif‚ Lennynin elinde bulunan bir klibi ele geçirmek için hayatını cehenneme çevirir. Yılbaşı kutlamaları yaklaşırken‚ bu esrarengiz klip Lennyyi umduğundan daha büyük bir komplonun içine itecektir. Kathryn Bigelowun kendi filmografisi adına bu sıradışı sayılabilecek yakın gelecek bilim kurgusu‚ görsel olarak baştan çıkarıcı olmanın yanısıra‚ meraklıları için hafif bir siber punk lezzeti de sunuyor. Tuhaf Günler‚ sürükleyici ve uzun finaliyle de izleyende bir tatmin duygusu bırakmayı biliyor.', 7.016, '1995-10-13', 4.4394, 1783119646278, 1783264868402, 1, NULL, 0),
(2, 318, 1, -1, '[10765,18,80]', 'American Gothic', '/qajOMTtQ958JEpmokPXTruwA9qp.jpg', '/itisXkOIsntQacvuO5BF05xHJ60.jpg', '', 7.4, '1995-09-22', 8.7835, 1783320720951, 1783320720951, 0, NULL, 0),
(2, 350, 0, -1, '[18,35]', 'Şeytan Marka Giyer', '/3hOdkmU8Y2C1vO1cyBcBVUmrj04.jpg', '/gkh6Nt8DtY1XT4gQsyFq9XAVJlJ.jpg', 'New York moda dünyasının göz alıcı karmaşasında, sıfır bedenli muhteşem kadınlar içindeyken saçınızın kötü olduğu bir gün iş hayatınızın sonu olabilir. İşte Runway Dergisi bu inanılmaz cehennemin tam ortasıdır. Miranda Priestly ise moda dünyasının en güçlü kadını Runway\'in korku salan kraliçesi kendisine bir asistan alacaktır. Milyonlarca kızın hayatını verebileceği bir iş ise sıradan bir New York\'ta yaşayan Andy Sachs için göz kırpmaktadır. Yapacağı iş kesinlikle kendisine saygısı olmayan insanların yapabileceği türden, yaşamı bırakıp çalışmaya dayalı bir tür Miranda köleliğidir.', 7.438, '2006-06-29', 51.5966, 1783320647786, 1783320647786, 0, NULL, 0),
(2, 389, 0, -1, '[18]', '12 Öfkeli Adam', '/jA3MHw8Nl4sevDqhgS8ZptwXN8b.jpg', '/qqHQsStV6exghCM7zbObuYBiYxw.jpg', 'Latin kökenli bir Amerikalı genç babasını bıçaklayarak öldürdüğü gerekçesiyle birinci dereceden cinayetle suçlanır ve mahkeme önüne çıkarılır.', 8.564, '1957-04-10', 25.2575, 1783266513842, 1783266513842, 0, NULL, 0),
(2, 393, 0, 2, '[28,80,53]', 'Kill Bill: Vol. 2', '/2yhg0mZQMhDyvUQ4rG1IZ4oIA8L.jpg', '/pgG6tzJzC8mjGqhaT8IWwEk00xf.jpg', 'Sıra dışı yönetmen Quentin Tarantino\'nun büyük beğeni kazanan dördüncü filmi olan, acımasız bir ihaneti ve destansı bir kan davasını konu alan heyecan ve gerilimi yüksek Kill Bill: Volume 2\'de Gelin (Uma Thurman, Pulp Fiction), intikamına kaldığı yerden devam etmektedir... Çoktan listesinde ki beş isimin ikisini haklayan Gelin\'in onur mücadelesi son hızıyla sürmekte ve artık kendisinin başlatmadığı ancak bitirmeye kararlı olduğu bu ölüm kalım savaşının sonlanması gerekmektedir. Tüm dünyada ses getiren aksiyon dolu nükteli bu film, mutlaka görülmesi gereken bir yapım.', 7.878, '2004-04-16', 10.5718, 1783281475284, 1783281475284, 0, '', 0),
(2, 424, 0, -1, '[18,36,10752]', 'Schindler\'in Listesi', '/2mOH8EqumIaepdP94e0cy4Xnyg7.jpg', '/zb6fM1CX41D9rF9hdgclu0peUmy.jpg', 'Tüm zamanların tarihsel açıdan en önemli filmlerinden biri olan Steven Spielberg\'in Schindler\'in Listesi, cesaret ve inanç dersleriyle nesiller boyu ilham vermeye devam eden güçlü bir hikaye. En İyi Film ve En İyi Yönetmen de dahil olmak üzere yedi Akademi Ödülü sahibi olan bu inanılmaz gerçek hikaye, Holokost sırasında 1.100\'den fazla Yahudinin hayatını kurtaran esrarengiz Oskar Schindler\'i (Liam Neeson) konu alıyor. Bu, fark yaratan bir adamın zaferi ve yaptıkları sayesinde insanlık tarihinin en karanlık bölümlerinden birini atlatanların dramıdır.', 8.57, '1993-12-15', 25.8176, 1783320689745, 1783320689745, 0, NULL, 0),
(2, 497, 0, 2, '[14,18,80]', 'Yeşil Yol', '/6ZNnKbdDRQm0ftkq3OKiDrwZkIN.jpg', '/b6HWTOxn1xevvyHU2K9ICvaRU6g.jpg', 'Edgecomb, hikayesini anlatırken bir huzurevinde yaşamaktadır ve hapishanedeki görevinin üzerinden yıllar geçmiştir. Hapishanedeki hücrelerinden alınan idam mahkumlarının elektrikli sandalyenin bulunduğu ölüm odasına giderken yürüdükleri, bir millik yeşil yolda yaşananlara her defasında tanık olan Edgecomb, ömrü boyu unutamayacağı olaylara tanık olur. Edgecomb, yıllar boyunca sayısız idam mahkumu nakleder ama hiç birisi onu John Coffey kadar etkilemez. Oldukça iri yarı bir adam olan Coffey, iki küçük kızı öldürmek suçundan idama mahkum olmuştur. Ürkütücü görünümünün aksine oldukça ince, kırılgan ve düşünceli bir yapıya sahip olan Coffey, bazı doğaüstü güçlere sahiptir. Edgecomb\'un ona gerçekten suçlu olup olmadığını sorması ile aralarında bir diyalog başlar.', 8.506, '2000-03-17', 30.6374, 1783265856083, 1783265856083, 0, '', 0),
(2, 507, 0, -1, '[28,80,18,53]', 'Killing Zoe', '/k3UEKMVnkljOlsO5sLmz87YGlaG.jpg', '/lA2EYuuyvWDDSL9rqONIByoQRDy.jpg', 'İki çocukluk arkadaşı Bastille Günü\'nde Paris\'te büyük bir banka soygunu gerçekleştirirler. Soygunculardan biri, bu bankada çalışan memurlardan biriyle ilişki yaşamaya başlar. Banka memurunun geceleri ek gelir elde etmek için fahişe olarak çalışıyor olması soygunu tehlikeye atar.', 6.198, '1993-10-01', 1.4497, 1783098238707, 1783264868402, 1, NULL, 0),
(2, 548, 0, -1, '[80,18,9648]', 'Raşomon', '/gpYADlpkoFTChBLjIrZU7hxDKz1.jpg', '/tDn1dA52bQH9B85vilHeU7C83W1.jpg', 'Ormanda devriye gezen polisler tarafından, öldürülmüş bir adamın cesedi bulunur. Adamın karısı da tecavüze uğramıştır. Olaya tanıklık eden üç kişi vardır: Bir gezgin, oduncu ve bir haydut. İzleyici olarak mahkeme bizizdir ve tanıkların hikayelerini dinleriz. Tecavüze uğramış kadın da dahil, hepsinin anlattığı hikayeler birbirinden farklıdır. Öldürülen adamın da olaya tanıklığını izlediğimiz filmde çözülmesi zor bir bulmacayla karşı karşıyayızdır: İçlerinden birileri yalan söylemektedir ancak kim ve neden? Film, 20. yy.\'ın başlarında yaşamış yazar Ryunosuke Akutagawa\'nın Ormanın Sıklığı isimli kitabının uyarlaması. Ancak, toplam süresi 60 dakikayı pek geçmeyine yazarın diğer kitabı Rashômon\'dan alınan kestilerin eklenmesiyle film son halini almış. Japon sinemasının ustalarından Kurosawa\'nın bu filmi pek ödüllendirilmemişse de oldukça başarılı. Rashômon insan psikolojisi üzerinde duran ve yalanın sınırlarını zorlayan bir Japon draması.', 8, '1950-08-26', 6.9588, 1783119597698, 1783264868402, 1, NULL, 0),
(2, 549, 1, -1, '[80,18]', 'Law & Order', '/haJ9eHytVO3H3JooMJG1DiWwDNm.jpg', '/tc7canPSAn2X14hYi6Rl3gZm1o4.jpg', 'Law &amp; Order, ABD kaynaklı bir mahkeme ve suç draması konulu bir televizyon dizisi. Dick Wolf tarafından yaratılan dizi 13 Eylül 1990 tarihinde ABD\'nin NBC televizyon kanalında yayına başlamıştır. New York kentinde geçen dizi bir grup savcı ve polis görevlilerinin meslek yaşamlarını konu almaktadır.Dizinin büyük bir başarı kazanması bu diziden türeyen Law &amp; Order: Special Victims Unit, Law &amp; Order: Criminal Intent, Crime &amp; Punishment, Law &amp; Order: Trial by Jury gibi çok sayıda benzer dizilerin yaratılmasına neden olmuştur.Law &amp; Order 2008 yılı itibarıyla ABD televizyonlarında en uzun süre gösterimde kalan dizi durumundadır.', 7.289, '1990-09-13', 210.862, 1783285343478, 1783285343478, 0, NULL, 0),
(2, 550, 0, 2, '[18,53]', 'Dövüş Kulübü', '/yjMuqAyJUoQZGWsZ0vZuYj5inAR.jpg', '/c6OLXfKAk5BKeR6broC8pYiCquX.jpg', 'Norton, hayatının sıkıcılığından kaçmak isteyen, kronik uykusuzluk çeken Jack rolünde. Her şey, Jack’in karizmatik ama çarpık bir felsefeye sahip sabun satıcısı Tyler Durden ile tanışmasıyla değişir. Tyler’a göre kişisel gelişim zayıfların işidir; asıl yaşamayı anlamlı kılan şey kendini yok etmektir. Kısa süre içinde Jack ve Tyler, bir barda otoparkta birbirlerini pataklamaya başlarlar — bu, onlara hayatın gerçek anlamını hissettiren bir tür arınma olur. Bu şiddetin keyfini başka erkeklere de tattırmak için, birlikte gizli bir Dövüş Kulübü kurarlar. Kulüp kısa sürede çılgınca bir başarı kazanır. Ancak Jack’i her şeyi altüst edecek şok edici bir sürpriz beklemektedir…', 8.438, '1999-10-15', 38.3121, 1783266073882, 1783266073882, 0, '', 0),
(2, 554, 0, -1, '[18,10749,35]', 'Guguk Kuşu', '/fYFe8mf3AIpE2cNve2qMqUx7k7o.jpg', '/1qwXItFKqvKYyW1CwbYhxyUC8Pj.jpg', 'Aşk ve savaş üzerine alışılmadık derecede sevimli, zeki ve komik bir film. “Guguk Kuşu”, Rus askerlerin Finli keskin nişancılara taktığı addır. Eylül 1944. Finlandiya, SSCB ile bir ateşkes antlaşması imzalayarak savaştan çekilir. Ama nefretin anlamsızlığının büsbütün ortaya çıktığı bir yerde, gözden ırak bir çiftlikte kıstırılmış olan filmin ana karakterleri bu gerçekten haberdar değildir. Gizli servisin tutukladığı Rus yüzbaşı İvan ile Finli keskin nişancı Veiko talihin bir cilvesi olarak aynı yere sığınmak zorunda kalır; burası, onlara düşman değil de birer erkek gözüyle bakan Anni adlı genç Lapon kadının çiftliğidir. Üçü, birkaç gün aynı yerde birlikte yaşamak zorunda kalır. Herbiri yalnızca kendi anadilini (Fince, Rusça, Laponca) konuşabildiği için, kimi komik, kimi trajik müthiş yanlış anlamalar ortaya çıkar.', 7.1, '2002-09-12', 1.455, 1783119614535, 1783264868402, 1, NULL, 0),
(2, 561, 0, 2, '[14,28,27]', 'Constantine', '/vPYgvd2MwHlxTamAOjwVQp4qs1W.jpg', '/x3YFn10ehQKMRIJwIfiDAX8S9Xt.jpg', 'Los Angeles\'ta özel dedektif olan John Constantine\'in doğaüstü olaylardaki başarısı yadsınamaz. Bu başarısının, kelimenin tam anlamıyla cehenneme gitmiş ve geri dönmüş olmasıyla yakından ilgisi vardır. Eliyle tutup gözüyle görmediği hiçbir şeye inanmayan polis memuru Angela Dodson, ikiz kız kardeşi esrarengiz bir şekilde intihar edince Constantine ile iş birliği yapmak zorunda kalır. İkili, cenennem yaratıkları ve iblisleri alt edip Los Angeles\'ın karanlık sokaklarında yollarını bulmak için birlikte savaş verirler.', 7.18, '2005-02-08', 20.4861, 1783119835110, 1783264868402, 1, NULL, 0),
(2, 590, 0, -1, '[18]', 'Saatler', '/4myDtowDJQPQnkEDB1IWGtJR1Fo.jpg', '/3oHFSEr4TRnsyTxWGrmY8Xi2FrR.jpg', 'Yıl 1923... Başarılı yazar Virginia Woolf, Londra\'nın dışındaki gözlerden uzak evinde Mrs. Dalloway isimli kitabını yazmaya başlar. Sağlık problemleriyle boğuşan Woolf, ağır bir depresyonun pençesindedir. Yıl 1951... Tutkuyla Mrs. Dalloway\'i okuyan ev kadını Laura Brown sahip olduğu hayattan kaçmanın tek yolunu böyle bulur. Yıl 2001... AIDS\'e yakalanan eski kocasının onuruna bir parti düzenleyen Clarissa Vaughan ve eski kocası Richard arasında Mrs. Dalloway üzerine kurulu özel bir bağ vardır. Bu film, farklı zaman dilimlerinde yaşayan üç farklı kadının bir gününü, Virginia Woolf\'un kült romanı Mrs. Dalloway ekseninde anlatmaktadır.', 7.255, '2002-12-27', 3.7904, 1783254634751, 1783264868402, 1, NULL, 0),
(2, 597, 0, 2, '[18,10749]', 'Titanik', '/hEntfzxB8yUXIxqZY929dELjLsi.jpg', '/xnHVX37XZEp33hhCbYlQFq7ux1J.jpg', 'Teknolojinin son sürat ilerlediği bir dönemde, insanlar üstesinden gelemeyecekleri hiçbir sorun olamayacağına inanmaya başlamışlardır. \'Titanic\' adlı dev transatlantik ise, insanlığın doğaya karşı gövde gösterisi gibidir. Bu \'Düşler Gemisi\' nin yolcuları arasında Avrupa`da birkaç yıl geçirdikten sonra Amerika\'ya dönmekte olan, Jack Dawson adlı genç ve fakir bir ressam ile nişanlısıve annesiyle Philadelphia`ya gidenRose DeWitt Bukater adlı zengin bir genç kız da vardır. İki genç şans eseri tanışacak, aralarındaki sınıf farkına aldırmaksızın birbirlerine yakınlaşacaktır. Yola çıkılmasından dört buçuk gün sonra, 10 Nisan 1912\'de, Titanic iki saat kırk dakika sürenve sulara gömülmesiyle son bulan, hazin olayların başlamasına neden olacak buz dağına çarpacaktır.', 7.9, '1997-12-18', 37.9108, 1783056128738, 1783264868402, 1, NULL, 0),
(2, 615, 0, 2, '[18]', 'Tutku: Hz. İsa\'nın Çilesi', '/ujlsPEegP3PRYXvMilR0nzl3C0W.jpg', '/4840rkbpsiuow5ew155oVKcqJwj.jpg', 'Nasıralı İsa, havarileriyle birlikte yediği son akşam yemeğinde kendisine ihanet edileceğini açıklamıştır. Tıpkı onun söylediği gibi Judas, İsa\'yı Romalılar\'a ihbar eder. Roma valisinin tereddütlerine karşın, Yahudiler\'in dini liderlerinin kışkırtmasıyla İsa\'ya tahammül edilemez işkenceler yapılır.', 7.545, '2004-02-25', 15.5109, 1783285338609, 1783285338609, 0, NULL, 0),
(2, 619, 0, -1, '[28,18,10749]', 'The Bodyguard', '/ihWF0uY1xnKqw9YK7ZHNLUZOhcO.jpg', '/bJyb7Bk9PLUslPggangniTBLzHO.jpg', 'Geçmişin gizli servis ajanı Frank Farmer \'ın, tehlikeli bir hayranı tarafından tehdit edilen ünlü pop yıldızı Rachell\'i koruma göreviyle yolları kesişir.. Önceleri, gözü güvenliği sağlamak dışında birşey görmeyen koruma ve özgürlüğüne düşkün pop yıldızı hiç anlaşamaz. Fakat daha sonra aralarındaki gerilim, aşka dönüşür. Kalbinin kapılarını aşka kapamış olan adam, aşkı ve sorumluluğu arasında sıkışıp kalmıştır. Sonuda elbette aşk galip gelir...', 6.704, '1992-11-25', 10.7016, 1783320707031, 1783320707031, 0, NULL, 0),
(2, 620, 0, -1, '[35,14]', 'Hayalet Avcıları', '/fTiiq21WmX9LDZFNzDSJZ6hWUYs.jpg', '/c6yfABGVKuB5cjoOwdX4AJMlzUz.jpg', 'Paranormal konulara düşkün Dr. Peter Venkman ve 3 kafadar akademisyen arkadaşı bir işe yaramadıkları gerekçesiyle Columbia Üniversitesi\'nden atıldıklarında kendi işlerini kurmaya karar verirler ve hayalet avcılığı şirketi Ghostbusters doğar.TV reklamları sayesinde isimlerini duyurup, New Yorkluları şehrin orasına burasına musallat olmuş hayaletlerden kurtarmaya başlarlar. Bir gün güzel viyolonselist Dana Barrett tarafında kiralandıklarında, genç kadına ait evin, New York\'u istila etmeye başlayan kötü ruhlar tarafından dünyaya giriş kapısı olarak kullanıldığını anlarlar. İşler kontrolden çıkar.1984\'te, o zamana dek yapılmış en pahalı komedi filmi olarak vizyona girdiğinde çılgınlık derecesinde sevilmiş olan Hayalet Avcıları; Dan Aykroyd ve Harold Ramis\'in birlikte yazdıkları dahice senaryo kadar, Bill Murray ve Rick Moranis gibi komedyenlerin usta oyunuyla da unutulmazlar arasına girmiş bir yapım.', 7.498, '1984-06-08', 9.1734, 1783119877064, 1783264868402, 1, NULL, 0),
(2, 624, 0, -1, '[12,18]', 'Easy Rider', '/3H3vwPGX6EbBRffIVHp3eHHcjka.jpg', '/qvTmYyYsv71qTq5syAq24k1kGk.jpg', 'Kült film sıfatını hakkıyla kazanmış filmlerin başında gelen Easy Rider, Hollywood’da başarılı ama bağımsız, karşı kültürel ve düşük bütçeli filmler dönemini başlatmıştır. Wyatt ve Billy adında iki motorcunun süslü Harley Davidson’ları üzerinde Los Angeles’tan doğuya doğru yaptıkları bu özgürlük arayışı, alternatif bir yol filmi olmakla birlikte iki kahramanın Amerikan rüyasına ulaşma yolunda bilinmezlerle dolu destansı yolculuklarını anlatıyor. Film, paranoyanın, bağnazlığın ve şiddetin hüküm sürdüğü konformist Amerika’da idealist 60’ların çöküşüne tanıklık ediyor. Filmde özgürlükler ülkesi olarak sunulan Amerika\'nın aslında kendi içerisinde farklılıklara ve bireysel özgürlüğe karşı ne kadar hoşgörüsüz bir tutum takındığından bahsedilmektedir.Zamane kuşağın bu mantaliteyi değiştirmeye çalışması ve kendi bakış açısını ortaya çıkarma çabası filmin ana temasını oluşturur. Film dönemin en eleştirel yapımlarından biridir..', 7.052, '1969-06-26', 3.9398, 1783119573748, 1783264868402, 1, NULL, 0),
(2, 655, 0, -1, '[18]', 'Paris, Texas', '/sP27Qm4THyRZyHjHYMfIDtJP6YE.jpg', '/fWrq3u16gaBJ6nYNWcR3XaOhQPq.jpg', 'Travis, sessiz bir adam. Sırlarını sadece yollarla paylaşıyor. Kırmızı şapkasıyla, çoğu insanın arabayla bile zor katlandığı yollara ayaklarıyla meydan okuyor.  Bir gün Travis kardeşinin davetiyle yeniden medeniyete dönüyor. Evde onu kardeşinin eşi ve kendi oğlu beklemektedir. Başta uygar ve kuralcı bir yaşamı dışlayan Travis oğlu için katlanmaya başlar. Hatta alıştıkça, uzun süre ertelediği bir şeyi yapmaya karar verir. Yeniden yollara dönmeden önce, eski karısını bulmak...  Wim Wenders\'in filmi, tüm zamanların en etkileyici filmleri arasına rahatlıkla girebilir. Olağanüstü karakter çalışması, yerleşik hayatı ve konformizmi tartışması ve tabii müthiş karşılaşmayı konu edinen unutulmaz son sahnesi bu filmi 20. yüzyılın zirvelerinden biri yapıyor.', 8.1, '1984-07-16', 6.2255, 1783191876678, 1783264868402, 1, NULL, 0),
(2, 670, 0, 3, '[53,9648]', 'İhtiyar Delikanlı', '/xpa9ybm6tYGna5LseqSXvKpSSJn.jpg', '/sdwjQEM869JFwMytTmvr6ggvaUl.jpg', 'Oh Dae-su, bir gün kendisini küçük karanlık bir hücrede bulur. Oraya kimler tarafından ve niye kapatıldığını bilmeyen adamın dünyayla bağlantısı sadece hücresindeki küçük televizyondur. Haberlerde karısının öldürüldüğünü duyunca olayla bağlantısı olduğu düşünüldüğü için kapatıldığını anlar. 15 yıl sonra, serbest bırakılan adam, ailesini öldüren kişileri bulmaya ve kendisini oraya kapatanlardan intikam almaya karar verir.', 8.234, '2003-11-21', 13.9152, 1783280524399, 1783280524399, 0, '', 0),
(2, 680, 0, -1, '[53,80,35]', 'Ucuz Roman', '/AgY33Wtg4737MhYopJSFyKWhKsO.jpg', '/suaEOtk1N1sgg2MTM7oZd2cfVp3.jpg', 'Jules Winnfield ve Vincent Vega, mafya babası patronları Marsellus Wallace’tan çalınan bir çantayı geri almaya giden iki profesyonel tetikçidir. Wallace aynı zamanda Vincent’a, kendisi birkaç gün sonra şehir dışındayken karısını dışarı çıkarmasını söyler. Butch Coolidge, bir sonraki maçını kaybetmesi için Wallace’tan para alan yaşlı bir boksördür. Honey Bunny ve Pumpkin, yer değişikliğine ihtiyaçları olduğuna karar veren soyguncu bir çifttir. Görünüşte birbirleriyle alakası olmayan bu insanların hayatları, hem heyecanlı hem de eğlendirici bir sinema filmi macerasında nefes kesici bir şekilde birleşecektir.', 8.482, '1994-09-10', 39.4519, 1783056438751, 1783264868402, 1, NULL, 0),
(2, 687, 0, -1, '[18]', 'Ölüm Yolunda', '/eShxyjhWoFl3BwsuEmVsr4nLaMZ.jpg', '/gwRWQeHfPuA8mg73kydQsM8rdXq.jpg', '\"Cesur ve Tutkulu Bir Dram\"  Bir rahibe ile mahkumun gerçek hikayesinden esinlenilen, Susan Sarandon\'a 1995 yılında en iyi kadın oyuncu dalında Oscar®, Sean Penn\'e de en iyi aktör dalında Oscar® adaylığı kazandıran bu muhteşem film, suç, ceza ve bedel ödemenin kışkırtıcı sınavını gözler önüne seriyor. \"Ölüm Yolunda\" sizi başından sonuna kadar merak içinde bırakacak, zeki sahnelerle bezeli, sürükleyici bir film. New Orleans\'lı rahibe Helen Prejean, idama mahkum edilmiş kızgın ve karmaşık katil Matthew Poncelet\'in manevi akıl hocasıdır.  Rahibe Helen kendini başkalarının kurtuluşuna adamıştır, Matthew\'a da aynı şekilde davranır. Ancak Matthew\'in karanlık ruhunun derinliklerine indikçe, aklını tamamen farklı bir soru kurcalamaya başlar: Bir insanın bedel ödemesinin sınırı nedir? Matthew\'un kaçınılmaz idamını engelleyebilecek midir? Yoksa tüm hayalı boyunca inandıklarını sarsacak bir gerçek mi keşfedecektir?...', 7.325, '1995-12-29', 3.3459, 1783285331816, 1783285331816, 0, NULL, 0),
(2, 693, 1, -1, '[9648,18,35]', 'Desperate Housewives', '/sywYmV9c9Vj2U7ocqNyfDt2pz3r.jpg', '/hW9NOFs8xUevb90KQYHhbifp9Po.jpg', 'Herkesi şaşırtarak, beklenmedik bir anda intiharı seçen Mary Alice Young, “oralardan bir yerden” dört yakın arkadaşının yaşadıklarını anlatıyor. Dört ev kadınının rutin yaşamları ne kadar sıkıcı ve tekdüze görünse de işin gerçeği hiç de öyle değil. Lynette, Tom\'un gayri meşru çocuğu ve onun annesiyle başa çıkmaya çalışırken, Susan ise komadaki Mike\'ın uyanıp ona dönmesini beklemektedir. Bree yeni tanıştığı Orson ile kötü günleri geride bırakmaya çalışacak, ama Orson\'un geçmişi peşlerini bırakmayacak gibi görünüyor.', 7.9, '2004-10-03', 96.0686, 1783056416372, 1783264868402, 1, NULL, 0),
(2, 705, 0, -1, '[18]', 'Perde Açılıyor', '/blBzZaatPWVuWpXEnPscMA4Xp6m.jpg', '/zAL3LOswagN9onjN8DPcNFTqKuD.jpg', 'En İyi Film başta olmak üzere tam 6 Oscar\'lı bir başyapıt  Ünlü yıldız Margo Channing (Bette Davis), Eve (Anne Baxter) adlı genç bir kızla tanışır Eve, Margo\'nun büyük bir hayranıdır ve kısa sürede onun güvenini kazanmayı başarır; hatta onun evine taşınır Oysa masum görünüşlü bu kızın başka amaçları vardır Margo\'nun yerini almak isteyen Eve, sinsi planlarını sırayla uygulamaya başlamıştır Margo\'nun yıldızı sönerken Eve ise başarıdan başarıya koşmaktadır...', 8.075, '1950-11-09', 3.2302, 1783285311880, 1783285311880, 0, NULL, 0),
(2, 764, 1, -1, '[80,18,9648]', 'Midsomer Murders', '/pz7tsWxe0TTdfJnWPjZAEnrSl5M.jpg', '/qVmgq1KXBp6BF2EqYPPaUG9iUGy.jpg', '', 7.489, '1997-03-23', 158.3244, 1782797072812, 1783264868402, 1, NULL, 0),
(2, 781, 0, -1, '[18,10749]', 'Winterschläfer', '/6GnzOfZbAuxPv7uuQetR0IySbMH.jpg', '/7KB5MLHBkkZrjKIZm5PRhImOSdt.jpg', '', 6.921, '1997-10-30', 0.3563, 1783119728153, 1783264868402, 1, NULL, 0),
(2, 782, 0, -1, '[878,18]', 'Gattaca', '/eSKr5Fl1MEC7zpAXaLWBWSBjgJq.jpg', '/hPsCR1ny6GnctJkWqeJwihTDD7T.jpg', '21. yüzyılda genetik mühendisliği çok gelişmiş ve bilimsel olarak kusursuz insanlar yaratılmaktadır. Özel pozisyonlar için yetiştirilen bu yeni süper insan ırkı yüzünden, normal yollardan dünyaya gelmiş insanlar işsiz kalmakta ve ikinci plana itilmektedir. Onlardan biri olan astronot adayı Vincent, Gattaca şirketinde ancak temizlikçi olarak iş bulabilecekken, komadaki bir atletin kan örneklerini ve kimliğini alarak iyi bir pozisyonda işe girer. Fakat şirkette işlenen bir cinayet, olayı araştıran dedektifin dikkatini Vincent\'ın üzerinde yoğunlaştırmasına sebep olacaktır.', 7.569, '1997-07-09', 6.6656, 1783119519757, 1783264868402, 1, NULL, 0),
(2, 795, 0, -1, '[10749,18,14]', 'Melekler Şehri', '/pR9ZMcdW5CGRz0bW2VlZSMe2G7G.jpg', '/pYl4YpepgRbr504D7ep58C5gMyF.jpg', 'Hastalarından birini hiç sebep yokken ameliyat masasında kaybeden kalp cerrahı Dr Rice\'ın kendine güveni alt üst olmuştur. Los Angeles üzerinde gezinen melek Seth o sırada her ne kadar ölen hastaya yardım için orada bulunsada Maggie\'den etkilenir ve onun kendine olan güvenini tekrar kazanmasında yardımcı olmaya karar verir. Bu arada ona aşık olur ve sonunda bütün risklerine rağmen görünmez bir ruh olmaktan çıkar, şüpheli bir yabancı haline gelir. Kadere inanmayan Maggie ise Seth\'e daha öncekilerle kıyaslanmayacak derecede aşık olur. Bu arada Maggie ile beraber olmak için göklerden ve meleklikten vazgeçen Seth, yeryüzündeki karmaşık hayatı yaşadıkça umutsuzluğa kapılır. Acaba aşk, kişinin temel özelliklerinden vazgeçebileceği kadar değerli midir?', 6.819, '1998-04-10', 4.6077, 1783119570847, 1783264868402, 1, NULL, 0),
(2, 797, 0, -1, '[18]', 'Persona', '/mAE4uwrXLlzo5AAxEorFvErdumq.jpg', '/amr72SENYz7AM4Hq5WBXxFBJEY6.jpg', 'Dönemin en gözde tiyatro oyuncusu güzeller güzeli Elisabet Vogler (Liv Ullmann), önemli bir piyes sırasında aniden susar. Şaşkına dönen insanlar ne olup bittiğini anlayabilmek için ellerinden geleni yapsalar da Vogler konuşmamaya devam eder. Son çare olarak bir kliniğe yatırılan kadın burada da dilsizliğine devam eder. Bedeninde tıbbi olarak hiçbir problem bulunamayan Vogler, doktorun tavsiyesiyle gözlerden uzak bir yazlığa gönderilir. Vogler’a genç bir hemşire olan Alma (Bibi Andersson) eşlik eder. Yazlıkta da Vogler\'in ağzını bıçak açmaz. Vogler sustukça Alma konuşur. Alma saatlerce, günlerce kendi hikayesini anlatır. Sonunda meydana gelen şey ise psikoloji biliminin en ilginç vakalarından birini oluşturacaktır.', 8.125, '1966-10-18', 3.8573, 1783098198914, 1783264868402, 1, NULL, 0),
(2, 814, 0, -1, '[35,27,14]', 'Kurt Adam Londra\'da', '/plyGF6KTc75lNpBD1RKOLZFPwTm.jpg', '/4js6VLf6qHWUbW42BpXiQKPBP7t.jpg', 'Amerika\'dan gelen iki genç öğrenci, İngiltere kırsalında ne olduğunu anlamadıkları bir yaratığın saldırısına uğrar. Arkadaşını bu saldırı sonucu kaybeden David ise hayatta kaldığına pişman olacaktır. Çünkü, lânet artık onun da kanına girmiştir.', 7.397, '1981-08-21', 4.8856, 1783119872515, 1783264868402, 1, NULL, 0),
(2, 819, 0, -1, '[80,18,53]', 'Kardeş Gibiydiler', '/g9pKy88BJLHp41u6vMmHnnaOmrk.jpg', '/sDhABATFQX8nfTHShTfH8HeqKY1.jpg', '1960\'larda Hell\'s Kitchen\'da büyüyen Shakes, Michael, John ve Tommy adındaki 4 çocuk, eşek şakası yaparken yaşlı bir adamın yaralanmasına neden olurlar. New York\'taki Wilkenson Center\'da 1 yıla yakın hapsolan 4 arkadaş, buradaki gardiyanların kötü muamelesine maruz kalır. Burada dayak yiyen, onurları zedelenen ve cinsel istismara uğrayan bu 4 arkadaş, 13 yıl aradan sonra Wilkenson ve gardiyanlarından intikam alma fırsatını yakalar.', 7.597, '1996-10-18', 12.5966, 1783098191387, 1783264868402, 1, NULL, 0),
(2, 824, 0, -1, '[18,10749,10402]', 'Kırmızı Değirmen', '/buCJwLboLxpg88zapgLQWGYHhgR.jpg', '/vvcLSgiviCIU0J0UcwLqWdU8Iup.jpg', 'Gerçeğin, güzelliğin, özgürlüğün ve aşkın kutlamasının yapıldığı 1900\'lü yılların göz alıcı, parlak fakat kötü şöhretli gece kulübünün adıdır Moulin Rouge... Satine, bu gece kulübünün parıldayan elması, en güzel yıldızı ve şehrin en tanınmış fahişesidir. Ama gece kulübünü finanse edecek zengin bir adamın takıntısı olmakla, gerçekten aşık olduğu beş parasız bir şair arasında seçim yapmak zorunda kalacaktır.', 7.527, '2001-05-18', 5.112, 1783119786207, 1783264868402, 1, NULL, 0),
(2, 833, 0, -1, '[18]', 'Umberto D.', '/mbkQ4A04Er9WJNudlVZH5HS8IMf.jpg', '/oHL7gjqFgxHiwm45hqj4Xou9Odg.jpg', 'İtalyada 2. Dünya savaşı zamanlarında geçer hikayemiz. Umberto Domenico Ferrari 30 yılını devlete vermiş bir emeklidir, Umberto D. pansiyon sahibesi tarafından 20 yıldır kaldığı odadan çıkarılmak istenir ama direnir ve de belli bir süre onunla savaşır. Hikayemizin ana karekteri Umberto D. kadar köpeği Flick de bize bu hikayede yol gösterici rolünü üstlenmiştir. İki canlı bir oda da sonunda barınamaz hale gelirler ve de sonunda Umberto D. anlayacaktır ki bu dünya artık o eski dünya değildir herşey değişmiş ve de vefasızlaşmıştır...', 7.87, '1952-01-20', 1.5222, 1783098078019, 1783264868402, 1, NULL, 0),
(2, 840, 0, -1, '[878,18]', 'Tehlikeli İlişkiler', '/6FIFkMInllxVvvnCogNYzmCCSnH.jpg', '/yBCekmb7vK70xUhtsRQBcTu65sB.jpg', 'Issız bir yolda kamyonetiyle gitmekte olan Roy Neary birden motorun garip çalışması yüzünden durmak zorunda kalır ve dışarı çıktığında da tepesinden gelen çok güçlü bir ışığın rahasız edici parlaklığı altında kalır. Bu durumdan çok etkilenen Roy, aradan geçen zaman içinde garip hayeller görmeye ve 5 notadan oluşan bir müzik sesi duymaya başlamıştır. 1945 yılında kaybolduğu kayıtlarda bulunan uçaklar Mojave Çölünde ortaya çıkar. Havayollarına ait bir yolcu uçağı da pilotun ne olduğunu söyleyemediği çok parlak bir cisim gürdüğünü rapor eder. Bütün bu olaylar Birleşik Devletler Hükümetini bu uzaylı yaratıkların nereye inmeyi düşündüklerini bulmak ve paniğe neden olmaması için, halkın oradan uzak durmasını sağlamaya yarayacak bir bahane yaratma çabalarına girmesine neden olur.', 7.352, '1977-12-14', 7.9625, 1783285449986, 1783285449986, 0, NULL, 0),
(2, 857, 0, 3, '[10752,18,36]', 'Er Ryan\'ı Kurtarmak', '/b9QqS5Hz1CqT16ZxwxJqwzCfIgr.jpg', '/bdD39MpSVhKjxarTxLSfX6baoMP.jpg', 'Dört çocuk annesi bir kadın, İkinci Dünya Savaşı’nda kaybettiği üç oğlunun ardından fazlasıyla yaralanmıştır. Şimdi tek dileği hayatta kalan tek oğlunun savaştan sağ salim dönmesidir. Yakarışları karşılık bulur ve Başkan tarafından verilen bir emirle James Ryan’ın ne pahasına olursa olsun bu savaştan sağ çıkması sağlanacaktır. Normandiya çıkarmasının yapıldığı gün, sekiz kişilik bir asker birliği farklı bir göreve, Ryan’ı kurtarma görevine atanır. Ancak yüzbaşı John Miller tarafından yönetilen bu birim, can pazarının yaşandığı bu zorlu ortamda hakikatli bir yaşam mücadelesine atılacak; tek bir adamı kurtarmak için sekiz kişinin hayatının tehlikeye atılmasının meşruluğunu sorgulayacaktır.', 8.228, '1998-07-24', 35.4463, 1783056224664, 1783264868402, 1, NULL, 0),
(2, 859, 0, -1, '[18,10749]', 'Tehlikeli İlişkiler', '/wnGa1AuT90QqD3m8TGs2Fv5asdu.jpg', '/xH9mjObdAatWoHpT912DDK8hEYG.jpg', 'Başkalarının hayatına müdahale etmekten ve onlarla oynamaktan büyük bir zevk alan Marquise de Merteuil\'in yeni hedefi, eskiden birlikte olduğu adamla beraber olan kuzeninin kızı Cecile\'dir. Bakire olan kızı baştan çıkarması için bu konularda usta olan ortağı Vincomte de Valmont’u ikna etmeye çalışır. Valmont için çocuk oyuncağı gibi duran bu durum onun hiç ilgisini çekmemektedir aslında. Onun hedefinde halasının evinde kalmaya başlayan Madam Tourvel’dir. Valmont’un kötü ününden haberdar olan Cecile’in annesi Madam Volange’ın Tourvel’i Valmont’a karşı doldurması yüzünden amacına ulaşamayan Valmont, kadından intikam almak için kızı Cecile’e yönelecektir. Öte yandan en önemli kuralını bozmuş ve Tourvel’e aşık olmuştur.', 7.201, '1988-12-21', 4.0188, 1783119575462, 1783264868402, 1, NULL, 0),
(2, 860, 0, -1, '[18,878,53]', 'Savaş Oyunları', '/zZ1rN4LoPxKNfAp67Xl300WxVeD.jpg', '/qtamfYGFfDLfGRcucx1zNwohRts.jpg', 'David Lightman, çevresiyle iyi ilişkileri olan, meraklı bir gençtir. David, bir şirkete ait sandığı bilgisayar sistemini hack ederek, orada bulduğu bir bilgisayar oyununu oynamaya başlar. Ancak onun oyun sandığı şey, aslında Amerikan\'ın askeri savunma sisteminde yer alan ve nükleer füzelerin kontrolünü sağlayan bir simülasyondur. Basit bir savaş oyunu oynadığını düşünen genç hacker, kendini Üçüncü Dünya Savaşı\'nın içinde bulur.', 7.068, '1983-06-03', 5.8772, 1783119715107, 1783264868402, 1, NULL, 0),
(2, 868, 0, -1, '[80,18]', 'Tsotsi', '/lBWnlgpcQ0LjDSR0ZNje51xPCFj.jpg', '/gLxgqHpJcMvB6cMTA4hUBxoOMJ1.jpg', 'Johannesburg’da küçük çaplı suçlar işleyen Tsotsi, zor hayatının sebep olduğu duygusuz bir yapıya sahiptir. Bir soygun işinde bir adamı vurduktan sonra tüm hayatını değiştiricek olaylar cereyan etmeye başlar. Oradan kaçmak için arabasını kaçırdığı bir kadını karnından vurur, ardında da arka koltukta başıboş bir bebek olduğunu fark eder. Bebeği alıp kaçan Tsotsi, altı gün boyunca bebeğe bağlanır, bebek de onun tüm davranışlarını ve hayatını değiştirmeye başlar.', 6.949, '2005-12-23', 1.1669, 1783098090206, 1783264868402, 1, NULL, 0),
(2, 869, 0, -1, '[53,878,28,12]', 'Maymunlar Gezegeni', '/1Dfc81RysEY0aJuZJUTTKrWOa7C.jpg', '/1N0MYYFvYwpM5fi3mjw4150ReoR.jpg', 'Yıl 2029... Astronot Leo Davidson, rutin bir uzay görevi sırasında yaşanan arıza nedeniyle \'ilginç\' bir gezegene düşer. Gezegenin ilginçliği, burada insanla maymun arası yaratıkların hüküm sürüyor olmasındandır. Aynı zamanda insanların da yaşadığı, ama artık sadece köle olarak kullanıldıkları bir gezegendir burası. Bu gezegenden kurtulmanın hesaplarını yapan Leo, şaşırtıcı gerçeklerle yüzleşeceğinin farkında değildir.', 5.771, '2001-07-26', 6.5742, 1783119869623, 1783264868402, 1, NULL, 0),
(2, 870, 0, -1, '[18,10749]', 'Bebekler', '/gEI8JJPayOrdfy0AjdWQ92A90cc.jpg', '/cxULojvpOWYX8AUG5eJpTYS8IbX.jpg', 'DOLLS, aşkın mantığa üstün geldiği; acının, hüznün ve kalp kırıklığının hüküm sürdüğü büyülü bir evrende İçiçe geçen paralel üç öyküden oluşuyor. Nişanlısı tarafından terkedilen genç bir kız başarısız bir intihar girişiminde bulunur. Genç kız kurtulsa da tüm bilincini yitirmiştir. Çevresiyle ilişkisi üç yaşındaki bir çocuktan farksızdır. Genç kızın nişanlısı hatasını anlayıp pişmanlık duysa da, hissettiği suçluluktan kurtulumaz. İki sevgili sonu belirsiz bir yürüyüşe çıkarlar. Öte yandan yaşlı bir yakuza, bir ömür geç kaldığı aşkını bulmuştur. Ancak zaman, yakuzanın hayatında gördüğü tüm savaşçılardan daha acımasızdır. Tüm bunların uzağında, şehrin başka bir yerinde ise bir başka genç, televizyonda gördüğü bir pop sanatçısına aşık olur. Genç adam, aşkına ulaşmak İçin herşeyini feda etmeye razıdır, gözlerini bile.', 7.5, '2002-10-12', 1.7098, 1783119524872, 1783264868402, 1, NULL, 0),
(2, 874, 0, -1, '[18,36]', 'Her Devrin Adamı', '/1AhIatyuSxymFNHhNTzDiUrE6kn.jpg', '/ulO2vXHo8oTOdUWSEwWkGFhq3VL.jpg', 'Başka bir kadınla evlenmek için karısını boşamak isteyen 8. Henry ile bu duruma ister istemez karışan Sir Thomas More\'un öyküsü  En iyi film, yönetmen ve aktör (Paul Scofield) dahil alti dalda Oscar kazanan \"Her Devrin Adami\", Leo McKern ve Orson Welles\'li kadrosuyla gerçek bir klasik.', 7.334, '1966-12-13', 1.9797, 1783119529115, 1783264868402, 1, NULL, 0),
(2, 877, 0, -1, '[80,28,18,53]', 'Yaralı Yüz', '/y4E5oRiHMTFkEB12IIcpbKbKzDW.jpg', '/bIv1kaxb7tsiZYPO27PHfVb5eSF.jpg', 'Brian De Palma 1980’li yıllarda üç saatlik bir şölene dönüştürdüğü Tony Montanalı SCARFACE hikâyesini yakın tarihe kadar bir gizem olan 1931 yapımı SCARFACE filminden aktarmıştır. Hayatı sinema filmine konu olan Howard Hughes, senaryo yazarı Ben Hecht ve Amerikan sinemasının efsane yönetmenlerinden Howard Hawks’ın 1931 yılında gerçekleştirdikleri bu eser “Klasik” ve “Yön verme” vasıflarını hak eden bir çalışmadır. Eserin ana fikri Tony Guarino isimli karaktere dayandırılan Armitage Trail’in aynı isimli romanına dayanmaktadır.Ufak işlerde pişen Sicilya kökenli serseri Tony Camonte, dağlı teknikleri ve megaloman seviyede ki kazanma hırsıyla Chicago Yeraltı Dünyasının en büyüğü olmaya yemin etmiştir. Bu yolda da kendi patronundan şehri yönetenler kulübünün üyelerine herkes birer araçtır. Sırası gelenler bu hırstan kendine düşen payı alacak ve hastanede ki suikast sahnesinde olduğu gibi bir buket çiçek ve kurşunla şehirden ve hayattan uğurlanacaktır.', 7.403, '1932-04-09', 4.1414, 1783285429296, 1783285429296, 0, NULL, 0),
(2, 880, 0, -1, '[18,35]', 'Antonia\'nın Yazgısı', '/774YCGVNZUJ5TTAmk80u37SHqUN.jpg', '/sOkUBkwq21ZEThCX7wboY2Xl3m5.jpg', 'Küçük bir Hollanda kasabasında, hayatı boyunca etrafındakilere ilham olmuş güçlü bir kadın geçmişini hatırlar. Sofrasında yemek yemiş, onun çatısı altında büyümüş nesilleri, dava arkadaşlarını, arkasında bıraktığı değerleri gözden geçirir.', 6.883, '1995-09-21', 1.7485, 1783320724626, 1783320724626, 0, NULL, 0),
(2, 925, 0, -1, '[18]', 'Doğruyu Seç', '/63rmSDPahrH7C1gEFYzRuIBAN9W.jpg', '/oYOZay9hyW3uI5paKWLIYkWZlzv.jpg', 'New York Brooklyne’de, yılın en sıcak günündeyiz. Mahallede geveze bir DJ’yin yeteneklerini sergilediği bir radyo istasyonu ve Koreli bir çiftin işlettiği bakkal dükkanı dışındaki yegane hareket merkezi, mıntıkanın bir beyazın işlettiği tek ticarethane olan pizzacıdır. Sal’ın Meşhur Pizzaları isimli dükkanda adamın birbirinden deli saçması iki oğlu ve bezgin siyahi Mookie çalışmaktadır.  Mookie’nin hayatında ise gereğinden fazla sorumluluk sahibi kızkardeşi Tina dışında, iki kankası, rap düşkünü sessiz Radio Raheem ve çabuk alevlenen mizacıyla Buggin\' Out vardır. Buggin’ bir gün Sam’ın dükkanında asılı bir İtalyan asıllı Amerikalılar köşesinde neden hep beyazlar olduğunu gündeme getirip mahalle çapında eylem yapmaya kalkar. Küçük aklıyla hesabedemediği şey ise, sinirlerin zaten gergin olduğu bu yılın en sıcak gününde olayların ne kadar kolay kontrolden çıkabileceğidir.', 7.767, '1989-06-14', 3.6859, 1783285380169, 1783285380169, 0, NULL, 0),
(2, 931, 0, -1, '[53,18,27]', 'Karanlığın Gölgesi', '/4A94Wy4E5O4hvDkX7tokRk6mrL8.jpg', '/8qi3gplNf48uLZnne09iiL4OvFG.jpg', 'Film, küçük kızlarını trajik bir şekilde kaybeden bir çiftin (John ve Laura Baxter) yaşadığı yas, suçluluk ve doğaüstü olaylar etrafında döner.\r John ve Laura, kızlarının ölümünden sonra acılarını hafifletmek umuduyla Venedik’e taşınır. John burada bir kilisenin restorasyon işinde çalışmaktadır. Ancak şehirde tuhaf ve karanlık olaylar yaşanmaya başlar.Laura, iki yaşlı kadınla tanışır — içlerinden biri medyumdur ve ölen kızlarının ruhuyla iletişim kurduğunu iddia eder. John ise bu duruma inanmaz, ama zamanla Venedik’te gördüğü kırmızı pelerinli küçük bir figür onu rahatsız etmeye başlar — tıpkı ölen kızına benzeyen bir figür', 6.921, '1973-10-11', 2.4437, 1783320701178, 1783320701178, 0, NULL, 0),
(2, 956, 0, -1, '[12,28,53]', 'Görevimiz Tehlike III', '/p2LbzVYLhIOjDleE19I12mgDAld.jpg', '/bYKeB9uUcPmvikjouEEQ86uvPw9.jpg', 'Gizli ajan Ethan Hunt beyazperdeye geri dönerken bugüne kadar karşılaştığı en amansız rakibini de yanında getirdi. Hunt ile ekibi bugüne kadar izini kimsenin takip edemediği silah satıcısı ve bilgi sağlayıcısı Owen Davian\'a karşı zor bir göreve soyunuyor.', 6.766, '2006-04-25', 12.2073, 1783119861933, 1783264868402, 1, NULL, 0),
(2, 979, 0, 2, '[18,53,80]', 'Dönüş Yok', '/nsGNiZHpJW2mxd4NlhF8vN5kP0f.jpg', '/xV1EfNSEg6id6juJPr1vM6p9x5X.jpg', '1998 Cannes Film Festivali ödüllü Seul Contre Nous\'un sansasyonel yönetmeni Gaspar Noé\'den, gösterildiği hemen her yerde yoğun tartışmalara ve ağır tepkilere hedef olmuş, aşk, tecavüz ve intikam üzerine sarsıcı bir film. Gösterildiği bazı ülkelerde, seyircilerin bayılmaları ya da koltukları parçalamaları gibi vakalara neden olan film, sansürlenip sansürlenmeyeceği tartışmalarını geride bıraktı ve nihayet huzurlarımızda.', 7.2, '2002-05-22', 34.8485, 1782797068683, 1782933622259, 1, NULL, 0),
(2, 1124, 0, 3, '[18,9648,878]', 'Prestij', '/wiSuje8hdVuwM0pvhtSFirCHmJF.jpg', '/z3br1ub7spqGMkxgjgJSdM4DC21.jpg', '19. yy sonlarında Londra’da Robert Angier, sevgili eşi Julia McCullough ve Alfred Borden hem arkadaştırlar hem de bir sihirbazın asistanlarıdırlar. Bir gösteri esnasında Julia ölünce Robert, onun ölümünden Alfred’i suçlar ve birbirlerine düşman olurlar. Zaman içinde ikisi de hem ünlü olurlar hem de rakip sihirbazlara dönüşerek birbirlerinin sahne üstünde performansını sabote etmeye kalkışırlar. Alfred başarılı bir hile yapınca Robert, rakibinin sırrını çözmek konusunu takıntı halinde getirir ve trajik olaylar birbirini kovalar.', 8.209, '2006-10-19', 20.2349, 1783271859232, 1783271859232, 0, '', 0),
(2, 1396, 1, 3, '[18,80]', 'Breaking Bad', '/ztkUQFLlC19CCMYHW9o1zWhJRNq.jpg', '/tsRy63Mu5cu8etL1X7ZLyf7UP1M.jpg', 'Kanserden öleceğini öğrenen bir kimya öğretmeni, ailesinin geleceğini garanti altına almak için metamfetamin üretip satmak üzere eski bir öğrencisiyle kafa kafaya verir.', 8.947, '2008-01-20', 137.8897, 1783265989034, 1783265989034, 0, '', 0),
(2, 1398, 1, -1, '[80,18]', 'The Sopranos', '/rTc7ZXdroqjkKivFPvCPX0Ru7uw.jpg', '/lNpkvX2s8LGB0mjGODMT4o6Up7j.jpg', 'New Jersey\'deki bir Amerikan-İtalyan mafya ailesinin babası olan Tony Soprano\'nun ve Soprano Ailesi\'nin diğer fertlerinin hayatlarından kesitler sunan dizi, toplamda 86 bölüm yayınlanmış, kazandığı ödüller ve aldığı olumlu eleştirilerle adını \"gelmiş geçmiş en iyi diziler\" arasına yazdırmıştır.', 8.673, '1999-01-10', 96.8129, 1783056323920, 1783264868402, 1, NULL, 0);
INSERT INTO `ratings` (`user_id`, `movie_id`, `is_tv`, `rating`, `genre_ids`, `title`, `poster_path`, `backdrop_path`, `overview`, `vote_average`, `release_date`, `popularity`, `created_at`, `updated_at`, `deleted`, `comment`, `is_spoiler`) VALUES
(2, 1399, 1, -1, '[10765,18,10759]', 'Game of Thrones', '/1XS1oqL89opfnbLl8WnZY1O1uJx.jpg', '/2OMB0ynKlyIenMJWI2Dy9IWT4c.jpg', 'Krallık dediğin savaşsız olur mu? En güçlü krallığı kurup huzuru sağlamış olsanız bile bu gücü elinizde nasıl tutardınız? Burada yanlış yapana yer yok, affetmek yok. Hanedan entrikaları, kapılı kapılar ardında dönen oyunlar, birilerinin kuyusunu kazmak için düşmanın koynuna girmekten çekinmeyen kadınlar, kardeşler arası çekişmeler, dışlanmalar. Hepsi tek bir amaç için: taht kavgası.', 8.464, '2011-04-17', 192.7225, 1783266501045, 1783266501045, 0, NULL, 0),
(2, 1402, 1, 2, '[10759,18,10765]', 'The Walking Dead', '/aN29llVoCFtBTwDZFtqdD9d8dHb.jpg', '/rAOjnEFTuNysY7bot8zonhImGMh.jpg', 'Dünyanın sonu bir zombi kıyametiyle gelmişken hayatta kalmayı başaranlar bu ölüm kalım mücadelesinde insanlığa karşı duydukları umuda tutunurlar.', 8.086, '2010-10-31', 110.0779, 1783056369108, 1783264868402, 1, NULL, 0),
(2, 1405, 1, -1, '[80,18,9648]', 'Dexter', '/q8dWfc4JwQuv3HayIZeO84jAXED.jpg', '/aSGSxGMTP893DPMCvMl9AdnEICE.jpg', 'O, \'ince ruhlu\' bir katil. O, Miami\'de yaşanan cinayetleri araştıran bir \'kan\' inceleme uzmanı. O, dünyaya adalet sağlamak için öldürüyor. Onun adı Dexter ve düzenin adaletini kişisel bakışa göre sağlamak hayatta kalma amacı.\n\nHem işinin ehli bir seri katil hem de sosyal kişilikli bir adam portresi çizen Dexter Morgan, 2006 yılından itibaren kendi ahlak anlayışına göre kötüleri yer yüzünden silmeye devam etti. Yayınlandığı yıldan itibaren onlarca televizyon ödülüne aday gösterilen, Emmy ve Altın Küre ödüllü Dexter, televizyon tarihinin de en sıra dışı karakterlerinden birini ekranlara taşıdı.', 8.239, '2006-10-01', 118.0871, 1783056399158, 1783264868402, 1, NULL, 0),
(2, 1407, 1, -1, '[18,10768,80]', 'Homeland', '/6GAvS2e6VIRsms9FpVt33PsCoEW.jpg', '/391ixi0wVbFtFLQnOy8ZncWv2io.jpg', 'Irak\'ta öldürüldüğü tahmin edilen bir Amerikan askeri, kaybolduktan 8 yıl sonra geri döner. Ancak eve dönüş sevinci sona erdikten sonra, onun gerçekten bir Amerikan kahramanı olup olmadığı ya da bir terör saldırısı planlayan uyuyan bir hücrenin parçası olup olmadığı konusunda şüpheler ortaya çıkar.', 7.584, '2011-10-02', 89.3467, 1783056412387, 1783264868402, 1, NULL, 0),
(2, 1408, 1, -1, '[18]', 'House, M.D.', '/3Cz7ySOQJmqiuTdrc6CY0r65yDI.jpg', '/r0Q6eeN9L1ORL9QsV0Sg8ZV3vnv.jpg', 'Gregory House New Jersey Princeton Plainsboro Hastanesinin tıbbi tanı uzamanı doktordur. Kendini aşırı beğenmesi, insanları önemsememesi ve boşvermişlik gibi özelliklerine rağmen müthiş bir doktordur. Uzmanlık alanı bulaşıcı hastalıklardır. Hiç kimsenin tanı koyamadığı hastalara tanı koyarak onların hayatlarını kurtarmaktadır ancak ekibindekilerin psikolojilerini de sürekli olarak bozmaktadır. Hastanenin yöneticisi Lisa Cuddy onu sürekli gözlem altında tutmaya çalışmaktadır ve ondan asla vazgeçmemektedir çünkü en zor durumlarda hastaları kurtaran hep odur ama Dr. House yüzünden hastane sık sık dava edilmektedir.', 8.566, '2004-11-16', 145.8806, 1783056131541, 1783264868402, 1, NULL, 0),
(2, 1412, 1, -1, '[80,18,10759]', 'Arrow', '/u8ZHFj1jC384JEkTt3vNg1DfWEb.jpg', '/wAFuDJfZJrnh6a1wf1Vt7PqYBvR.jpg', 'Şiddetli bir gemi kazasından sonra milyarder playboy Oliver Queen kaybolmuştur ve Pasifik’te ücra bir adada yaşadığı keşfedilinceye kadar, beş yıl boyunca ölü olduğu sanılmıştır. O sırada Oliver ada’da kendini eğitmiş bir çok sınavdan geçmiş ve hayat mücadelesi vermek zorunda kalmıştır. Evi Starling City’ye döndüğünde onu, üzerine titreyen annesi Moira, çok sevgili kız kardeşi Thea ve en iyi arkadaşı Tommy karşılar fakat onlar Oliver’ın adada çektiği sıkıntıların onu değiştirdiğini hissederler. Oliver tekrar ailesi ile bir araya geldiğinde henüz bilmediği bir çok sırrın olduğunu keşfeder. Arrow kimliğine büründüğünde zengin olmak için pis işlere karışan iş adamlarını öldürmek için savaşmaktadır.', 6.836, '2012-10-10', 128.7626, 1783056301278, 1783264868402, 1, NULL, 0),
(2, 1416, 1, -1, '[18]', 'Grey\'s Anatomy', '/hjJkrLXhWvGHpLeLBDFznpBTY1S.jpg', '/jP0Rhj9OTPDAwQlHQwOLFDdeE8t.jpg', 'Grace Hastanesi\'ne hoş geldiniz! Burada yeni ve acemi doktorlar için en zorlu doktorluk ihtisas devresi programlarından biri uygulanıyor. Bu acımasız eğitimle başa çıkmak zorunda olan kahramanlarımız ise Meredith, Izzie, George, Alex ve Cristina. Onlar dün öğrenciydiler, bugün ise doktor oldular. Eğer yedi yıl boyunca Grace gibi bir cehennemde başarılı olurlarsa cerrahlığa da hak kazanmış olacaklar. Ancak ihtisas devresinin bu kadar zorlu olması, onlar için yaşamlarının geri kalanının durdurduğu anlamına da gelmiyor. Yani bu grup, aynı zamanda kıskanç sevgililer, ebeveynler, tek gecelik ilişkiler ve ev bulma krizleriyle mücadele etmek zorunda. Üstelik kahramanlarımız, bu stresli ve rekabet dolu ortamda dostluklar da kurmaya çalışıyolar.', 8.21, '2005-03-27', 208.3906, 1783272222212, 1783272222212, 0, NULL, 0),
(2, 1423, 1, -1, '[18]', 'Ray Donovan', '/cwJ6nLNvX62By0yoLYWFhRelPkF.jpg', '/k1UpU2cfa4PbDUBnJtr43TpdNBg.jpg', 'Los Angeles\'in zengin ve ünlüleri, ne zaman başları sıkışsa Ray Donovan\'ı ararlar, ancak Donovan kendi ailesinin neden olduğu sorunları çözmekte o kadar da iyi değildir.', 7.5, '2013-06-30', 34.5948, 1783266476599, 1783266476599, 0, NULL, 0),
(2, 1425, 1, -1, '[18]', 'House of Cards', '/rXaHpG5E8y68pqfG2RRwmjdebo1.jpg', '/zoAxfThy7ntyCutBeNgdaKhRoSX.jpg', 'Beyaz Saray\'ın ihanetine uğrayan Kongre Üyesi Frank Underwood gücü ele geçirmek için mücadeleye başlar. Silahları şantaj, baştan çıkarma ve hırstır.', 8, '2013-02-01', 39.2535, 1783266471742, 1783266471742, 0, NULL, 0),
(2, 1427, 0, 3, '[80,14,18]', 'Koku: Bir Katilin Hikayesi', '/ybPGvKPA7N2WYtt0q625JyZcbKF.jpg', '/kvdy0Ijjo2r9qsnWV4Dzx07qwnc.jpg', 'Jean Baptiste Grenouille, 18.yy da Paris’te dünyaya gelmiş olup, son derece değişik bir karakterdir. Her türlü kokuya karşı sıra dışı bir algısı vardır. Duyarlılığı çok yüksektir. Öte yandan diğer duyuları aksine gelişmemiştir. Arzu ettiği kokulara sahip olmak uğrunda her şeyi yapmaya hazırdır. Buna insan öldürmek de dahil. Bir gün kendine ait bir ten kokusunun olmadığını fark eder. Bu durumda tek çare vardır. Ona insan kokusu gerekir. Yeni baştan yaratacağı bir insan kokusu. Bunu elde etmek için de insanlara gereksinimi vardır. Patrick Süskind’in aynı adlı romanından uyarlanan film, koku ile var olabilen Jean Baptiste’in trajedisini anlatmaktadır.', 7.369, '2006-09-13', 10.3621, 1783271879772, 1783271879772, 0, '', 0),
(2, 1431, 1, -1, '[80,18,9648]', 'CSI: Crime Scene Investigation', '/i5hmoRjHNWady4AtAGICTUXknKH.jpg', '/cvlLBcQWpO9X21jDHhgPJnE2aVq.jpg', 'CSI: Crime Scene Investigation suç mahali araştırmasını konu alan ABD kaynaklı bir dizi filmdir. Dizinin adı, Las Vegas\'da çekilmesi nedeniyle CSI: Las Vegas olarak da bilinir. Amerikan CBS televizyonu tarafından yayınlanan dizi 24 Emmy, 6 Altın Küre ödülüne aday gösterilmiştir.\n\nDizi Türkiye\'de TRT tarafından Kanıt Peşinde adı altında yayınlanmaktaydı. Dizide şef Gil Grissom ve ekibi her bölümde ayrı bir davaya/cinayete açıklık getiriyorlar.', 7.6, '2000-10-06', 134.9641, 1783056210443, 1783264868402, 1, NULL, 0),
(2, 1440, 0, -1, '[18,10749]', 'Tutku Oyunları', '/l2wTSP0Ifo9vY03nJEfkFBbT2S9.jpg', '/uDDgaNppSCJm6kWDLl7vMeu8xcl.jpg', 'Amerika\'nın banliyösünde \"Madam Bovary\"nin yankıları. Sarah, bir reklam müdürü ile yaptığı sevgisiz bir evliliğin içinde savrulurken kızı ile parkta, havuzda uzun saatler geçirerek daha fazlasını elde etmek istemektedir. Brad, bir belgesel yapımcısı ile evli olan olgunlaşmamış bir ev erkeğidir. Ronnie, hapisten henüz çıkmıştır ve yaşlı annesi May ile birlikte yaşamaktadır. Larry emekli bir polistir ve Ronnie\'nin kaçmasına engel olmuştur. Sarah ve Brad kesişirler. Ronnie ile Larry\'nin şeytanları vardır. Brad\'in bar için çalışması gerekir ve Larry işini kaybeder. Ronnie\'nin annesi de oğlunun bir kız arkadaşa ihtiyacı olduğunu düşünmektedir. Sarah, daha fazla bu mutsuz hayatın içinde sıkışık yaşamak istememektedir. Film boyunca tüm bu karmaşık hikayelerin, her birini nereye götüreceği merak konusu olur.', 7.09, '2006-10-06', 6.4603, 1783119552207, 1783264868402, 1, NULL, 0),
(2, 1495, 0, 2, '[18,28,12,36,10752]', 'Cennet\'in Krallığı', '/8eZs5SiPj5KDII4DTorXmBcrzE7.jpg', '/8itHQecANtOevcCdr3AhVxFCYkw.jpg', 'Gladyatör\'ün yönetmeni Ridley Scott\'tan cesaret, tutku ve macera dolu, destansı bir yolculuğa hazır olun. Ortaçağ Kudüs\'ünün entrika ve şaşaasının ortasında Orlando Bloom her şeyini kaybetmiş biriyken, şeref ve cesareti kendisini ziyarete gelen yürekli bir misafirde bulan genç Fransız Balian rolüyle göz dolduruyor. Yaşanan yenilgilere rağmen Balian, halkını kurtarmak ve gerçek bir şövalye olmak için ezici kuvvetlerle savaşır.', 7.059, '2005-05-03', 21.1509, 1783289292178, 1783289292178, 0, '', 0),
(2, 1579, 0, 3, '[28,18,36]', 'Apocalypto', '/cRY25Q32kDNPFDkFkxAs6bgCq3L.jpg', '/nnmbJvYyDS1VkMOCbxSpdBi3WbJ.jpg', 'Güçlü Maya Krallığı, gittikçe yayılan şehirler kurarak, gökyüzünü delen piramitler yaparak ve olağanüstü kültürel ve bilimsel başarılar elde eden etkileyici gelişmiş bir toplum inşa ederek Amerika’da 1000 yıldan fazla bir süre hüküm sürdü. Ondan sonra, tarihin ışıltısı içinde, bu dünya çöktü. Bütün bunlardan geriye kalan ormanlarla kaplı birkaç piramit ve boşuna umut veren bir gizem oldu. Şimdi, Maya uygarlığının sona ermesinden 500 sene sonra, yönetmen Mel Gibson, felaketin kıyısındaki bir dünyada kendisi için en fazla önem taşıyan şey olan ülkeyi kurtaracak olan bir adamın macerası üzerine kurulan belirli bir zamanı olmayan bir efsanede olduğu gibi her şeyi gözler önüne seren modern bir film macerası yaratmak için asla keşfedilmemiş bu ülkeyi derinlemesine araştırıyor.', 7.646, '2006-12-07', 26.1288, 1783280594414, 1783280594414, 0, '', 0),
(2, 1598, 0, -1, '[18,80,53]', 'Korku Burnu', '/8F3frV0RC7hwuStksz1N4OogA6r.jpg', '/ntgpger7OwFNlEldxuvvFHDKzjW.jpg', 'Sam Bowden hayatını kanuna adamış Atlanta\'da yaşayan bir avukattır. Ailesi ile birlikte sakin bir hayat süren Sam\'in hayatı yakında kabusa dönüşecektir, çünkü 14 yıl önce avukatlığını üstlendiği Max Cady isimli adam, hapisten çıkmıştır ve intikam için hazırlanmaktadır. Çünkü, Max Cady acımasız bir tecavüzle suçlanıyordu, okuma yazması da yoktu. Bu yüzden Sam eline Max\'in hapisten kurtaracak bir belge geçmesine rağmen yine de bunu kullanmaz ve Max Cady tutuklanır. Şimdi Max hapisten çıkmıştır. Önce küçük tehditlerle başlayan intikam hırsı, gittikçe Sam\'in ailesini de etkileyecektir. Sam\'in bir kadın avukat arkadaşına ilk başta tecavüz eden Max Cady, bu sayede karısı ile Sam\'in arasına açar ve evlerinde tartışmalar başlar. Max\'in çıktığı günlerde de Sam\'in evindeki köpek zehirlenerek öldürülür. Ve bu olaylar Max Cady için sadece başlangıçtır, daha sırada 16 yaşındakı kızları Danielle vardır.', 7.262, '1991-11-13', 8.0324, 1783098205904, 1783264868402, 1, NULL, 0),
(2, 1622, 1, -1, '[18,9648,10765]', 'Supernatural', '/8iixmfGx5EIFPdpNvB2JvI3VIqX.jpg', '/ro0tlgnsco4SwbdAgmscLkSlMSL.jpg', 'Evlerinin yandığı şüpheli bir yangında, annelerinin ölümünden sonra, Sam ve Dean Winchester yaşları büyüdükçe babaları ile yollarda bir hayat yaşamaya başlarlar. Yıllar geçer ve bir av sırasında kaybolan babalarını bulmak için kardeşler bir araya gelirler.\n\nAncak, babaları normal bir avcı değildir: o hayaletler, vampirler, ve ruhlar gibi doğaüstü yaratıkları avlar ve aynı şeyi oğullarına da çok küçük yaşlardan itibaren öğretmiştir. Yol boyunca, Sam ve Dean, masum insanları yaratıklar ve hayaletlerden kurtarmak için büyük bir mücadeleye girerler ve babalarının nerede olduğuna dair ipuçlarını toplarlar.', 8.311, '2005-09-13', 211.1009, 1783320678994, 1783320678994, 0, NULL, 0),
(2, 1900, 0, -1, '[53,18,80]', 'Trafik', '/jbccmnqE4oAPI67bApgt2JiRPz8.jpg', '/nkMgY1XFLWr91najzfvwie8LyYF.jpg', 'Muhafazakar bir yargıç, ABD başkanı tarafından uyuşturucuya karşı verilen savaşa öncülük etmek görevine atanır. Bu yeni misyonu sırasında, savcı kendi kızına ait çarpıcı gerçeklerle de yüzleşecektir.Uyuşturucu trafiğini farklı cephelerden ele alan ve bir biçimde bu işe bulaşmış insanların kendi küçük öykülerini iki saati aşan bir süreçte toplayan TRAFİK, İngiliz Channel 4 televizyonunda dört bölüm halinde yayınlanmış aynı adlı mini diziden esinle Alman - ABD ortak yapımı olarak gerçekleştirildi.', 7.096, '2000-12-27', 10.0822, 1783119616156, 1783264868402, 1, NULL, 0),
(2, 1901, 0, -1, '[35,18,10749]', 'Babamın Kabusu', '/5H3fbU4NlHPbLf3MUFZwPdmD3nS.jpg', '/ukShYvWPLrGBFdy1CvnKXR79oRV.jpg', 'Uzun zamandır haftalık Sports Amerika\'nın reklam satış bölümü başı olan 51 yaşındaki Dan Foreman\'ın hayatı yolunda görünmektedir. Sıcak ve dürüst pazarlık anlayışı sayesinde dergideki en büyük yılını yeni kutlamıştır. Karısının beklenmeyen hamilelik haberi ve büyük kızı Alex\'in New York Üniversitesi\'ne (ne kadar pahalı olduğunu söylemeye gerek yok) kabul edilmesi aile bütçesinde kimi sorunlara yol açabilecek olsa bile Dan\'i mutlu etmiştir. Her zaman olduğu gibi bunun da üstesinden gelecektir.', 6.048, '2004-12-29', 2.5468, 1783119762469, 1783264868402, 1, NULL, 0),
(2, 1904, 0, -1, '[18,10749,36]', 'Bir Geyşanın Anıları', '/pBwYsQaSTgnPphIy02DJjCF2cqs.jpg', '/zJDnqXtGNHUmexiaWNa52Vslve5.jpg', 'İkinci Dünya Savaşı’ndan bir yıl önce, yoksul bir ailenin kız çocuğu bir geyşa evinde hizmetçi olarak çalışmaya başlar. Gizemleri günümüze kadar korunan, saklı ve bir o kadar da büyülü bir dünyada büyüyen kız çocuğu, rekabetin bitmediği, hataların affedilmediği bir dönemde efsanevi geyşa Sayuri’ye dönüşür. Dönemin en güçlü erkeklerini parmaklarında oynatan Sayuri, rakiplerinin tuzaklarına aldırmaksızın gerçek aşkın hayalleriyle yaşamaktadır.', 7.636, '2005-12-06', 4.9669, 1783119631104, 1783264868402, 1, NULL, 0),
(2, 1909, 0, -1, '[10749,18,35]', 'Don Juan DeMarco', '/fe0TuYz9jCKUba2Omj48K8bWJ8z.jpg', '/nnrITCU29fAVFDngn3eEwBsECPX.jpg', 'Emekliliğine günler kalmış olan saygın psikiyatrist Dr. Jack Mickler (Marlon Brando),Zorro gibi giyinmiş bir genci (Johnny Depp) tam intihar edecekken kurtarır ve çalıştığı Psikiyatri kliniğine getirir. Bu genç kendisinin efsanevi Don Juan olduğunu ve ilk aşkını aramak üzere New York\'a geldiğini söylemektedir. Dr.Mickler kendisine tanınan 10 günlük süre içerisinde gencin hayat hikâyesini dinler ve gittikçe onun gerçekten Don Juan olduğuna inanmaya başlar. Bu on gün içinde ondan dinledikleri Dr.Mickler\'in de yaşantısını da etkilemeye başlar, eşi Marilyn (Faye Dunaway) ile olan ilişkisi canlılık kazanmıştır. Dr.Mickler kişilerin kendi gerçeklerini yaşamaya çalışmalarının onların deli olmaları anlamına gelmeyeceği sonucuna varır.', 6.8, '1994-10-12', 2.1583, 1783119742644, 1783264868402, 1, NULL, 0),
(2, 1911, 1, -1, '[80,18]', 'Bones', '/eyTu5c8LniVciRZIOSHTvvkkgJa.jpg', '/aSye04zKzWtUP3U6Cl4bOXc5Ih9.jpg', 'Dr. Brennan, küçük yaştayken anne ve babası bir anda ortadan kaybolduktan sonra yetimhanelerde büyürken, ebeveyinlerinin ortadan kaybolmasının gizemini çözmek için kendini antropolojiye adamış ve adli tıp antropoloğu olarak Jeffersonian Enstütüsünde çalışmakta olan, kelimenin tam anlamıyla dahi bir doktor ve bir ‘çok satan’ polisiye roman yazarıdır. Uzmanlık alanı kemikler ve kökenleri olan Brennan bu bilgisini Özel Ajan Seeley Booth’un cinayetleri çözmesine yardım etmek için kullanır.', 8.187, '2005-09-13', 131.961, 1783056156525, 1783264868402, 1, NULL, 0),
(2, 1912, 0, -1, '[35,18]', 'Her Şey Reyting İçin', '/tGoelL9ZBIiIHisc8G76DIi5SlS.jpg', '/pqVDgmktHuSAGdL7sDzQTd1MjJR.jpg', 'Rainer son derece başarılı bir televizyon yapımcısıdır. Hiçbir kriter gözetmeden imza attığı aptalca ve bayağı şov programları reytinglerde bir numarada yer alır Pegah\'ın neden olduğu araba kazası nedeniyle ölümden dönen Rainer, bir anda tamamen değişir. Ciddi programlar yapmaya başlar ama bu sefer de reytingler düşer. İşini bırakıp Pegah ve bir grup işsizle birlikte kendine ekip kuran Rainer, televizyondaki olumsuz gidişatı durdurmak için harekete geçer.', 6.711, '2007-09-11', 0.6217, 1783119542945, 1783264868402, 1, NULL, 0),
(2, 1922, 0, -1, '[18]', 'Irina Palm', '/3h7miVXulTHbpa4NWyUUcguO90e.jpg', '/sdiPGIHnizmdicPlcpzyPosBJTT.jpg', 'Orta yaşlı Maggie torununun hayatını kurtaracak tedavi için gerekli olan parayı bulmak zorundadır. Bütün maddi kaynakları tükenen Maggie, birgün \"Hostes aranıyor\" ilanı gözüne iliştiğinde ise kendini bir seks kulübünde bulur. Evini küçük Olly\'nin tedavi masraflarını karşılamak için çoktan satmış olan Maggie, son şansı olan bu işi kabul eder. Çekingen Maggie için seks dünyasındaki bu başlangıç oldukça zordur. İş arkadaşı Luisa, Maggie\'e yardımcı olur ve iki kadın arasında dokunaklı bir arkadaslık başlar. İşveren Miki işine bağlı Maggie\'yi arzulanan ve iyi kazanan \"Irina Palm\" a dönüştürür. Maggie bundan böyle kendini yaşlı ve işe yaramaz olarak görmeyecektir. Maggie inatla sessizliğini korur, paranın kaynağını kendi oğlundan bile saklar. Fakat ortaya çıkması kaçınılmazdır ve Maggie ikiyüzlülüğün çirkin yüzüyle ve vicdanıyla yüzleşmek zorundadır. Başını dik tutmaya çalışan Maggie aile sevgisinden başka şeyler de bulacaktır…', 6.9, '2007-02-13', 2.2517, 1783119468778, 1783264868402, 1, NULL, 0),
(2, 1935, 0, -1, '[18,35]', 'Les Sœurs fâchées', '/kvB5SYoP4qXzajrOgGvMVRl1Dh4.jpg', '/sgDWw9FP95fN01NvS39wgM8T3Cf.jpg', '', 5.6, '2004-11-21', 0.8515, 1783119731613, 1783264868402, 1, NULL, 0),
(2, 1955, 0, -1, '[18,36]', 'Fil Adam', '/u0wpPYjuSt8DIe1Y3Vapnh8jcKE.jpg', '/6huSptAsqYg3wbsi1jbMognSgmp.jpg', 'Victoria dönemi İngilteresi\'nde yaşayan John Merrick, ender görülen bir hastalık yüzünden ileri derecede deforme bir bedene ve yüze sahiptir. Gezici bir kumpanyada Fil Adam takma adıyla sergilenmekte ve kafes hayvanı muamelesi gördüğü çok zor bir hayat geçirmektedir.  Dr. Frederick Treves adında genç bir cerrahın onu içine hapsolduğu korkunç hayattan kurtarmasıyla hiç alışık olmadığı güzel bir dünyaya adım atar.  Ancak acı ve korku dolu geçmişi Merrick\'i bu yeni dünyada da takip edecektir.', 8, '1980-10-09', 6.0418, 1783119506759, 1783264868402, 1, NULL, 0),
(2, 1985, 0, -1, '[18,9648,53]', 'Arka Bahçe', '/nkXq7V7mmJVbvwZGr3nxkHo7HkS.jpg', '/ldPtMaobGaG7sSrKM1c9Vnd6UGq.jpg', 'Tanrıkent filmiyle dikkatleri üzerine çeken Fernando Meirelles, John Le Carre’ın çoksatan romanından uyarladığı Arka Bahçe’yi; yine kendine has, eşsiz bir üslupla sinemaseverlerle buluşturuyor. Arka Bahçe, Kenya’da vahşice öldürülen aktrist Tessa Quayle’in ölümünün ardındaki esrar perdesini kaldırmak isteyen kocası Justin Quayle’nin bireysel çabalarıyla ortaya çıkardığı büyük bir komployu anlatıyor.', 6.985, '2005-08-31', 7.4183, 1783285421155, 1783285421155, 0, NULL, 0),
(2, 2025, 0, -1, '[35,18]', 'Quelques jours avec moi', '/kOPfRCxaBcaNp3bVbYxNgeRT6hY.jpg', '/hMmhuLa1h6bUghyYF8pcigoSMQ6.jpg', '', 5.917, '1988-08-14', 1.0871, 1783119618169, 1783264868402, 1, NULL, 0),
(2, 2034, 0, -1, '[28,80,18]', 'İlk Gün', '/7WbbvBh3huLFUQN3w2lHJ6dx2oI.jpg', '/nuO8o9ltxhI7AZQxePavEZ4TyHa.jpg', 'Her gün Amerika\'nın arka sokaklarında bir savaş tekrarlanmakta. Uyuşturucu satıcıları, sıradan insanlar ve onları diğerlerinden korumaya yemiş etmiş insanlar arasında geçen bir savaş. 13 yıllık narkotik polisi Alonzo Harris, sokaklarda geçirdiği yıllar boyunca mesleğe ilk girdiği günkü idealistliğini kaybetmiş ve işleri kitaba uygun yapmaya çalışırsa hiç bir şey yapamayacağının ve kısa zamanda öldürüleceğinin bilincine varmıştır. Alonzo ve onun gibi bir çoğu artık gereken işi yapabilmeleri için korudukları kanunu çiğnemektedirler. Artık yaptıkları işin yasal olup olmadığı iyice bulanıklaşmıştır.Bir gün onun yanında göreve verilen çaylak polis Jake Hoyt ise Alonso\'dan çok farklıdır. Jake her işi kitabına uygun yapıp toplumu düzene sokmayı inanç edinmiş tam bir idealisttir.', 7.524, '2001-10-05', 5.8917, 1783119526387, 1783264868402, 1, NULL, 0),
(2, 2060, 0, -1, '[18,35]', 'Des enfants gâtés', '/yc3jbPLHJGtkjo6llVGlqY1rTJp.jpg', '/5R1ZAbsABbswu9jaGecRPZY25KP.jpg', '', 6.2, '1977-09-07', 2.2127, 1783119729808, 1783264868402, 1, NULL, 0),
(2, 2065, 0, -1, '[18,35,10749]', 'Je crois que je l\'aime', '/jYyuV50tnSvXNkEAaSvyezI84lx.jpg', '/zRHIkeHwcwfVZKnHXDfLwL3cfPS.jpg', '', 6.323, '2007-02-08', 0.405, 1783119798417, 1783264868402, 1, NULL, 0),
(2, 2266, 0, -1, '[18,10749]', 'Paris, Seni Seviyorum', '/w2ymaGlJqgNHjexYQ6h0ByoGzw8.jpg', '/z5SQmAzMAkK54qMQJC9WsZ6PddL.jpg', 'Paris\'te aşk her yerdedir. Barlarda, kafelerde, Eyfel Kulesi\'nin altında, metroda hep aşk vardır.\r Paris, seni seviyorum için çok sayıda uluslararası yönetmenden Paris\'te geçen romantik bir hikaye anlatmaları istendi. Projeye katılan tüm yönetmenler, Paris\'in zengin sinematografik tarihine rağmen, geriye bakmaktansa, Paris\'i bugünkü haliyle, beyaz perdeye hiç taşınmamış yönleriyle aktarmayı yeğlediler. Bu nedenle \"Paris, seni seviyorum\" farklı sosyal sınıflar, kuşaklar, kültürler ve atmosferlerin karışımı. Her yönetmenin, kentin çeşitli yerlerinde geçen farklı yaşam kesitleri sunduğu sevinç, ayrılık, beklenmedik garip rastlantılar ve her şeyden çok aşka dair hikayelerden oluşan, çiçek dürbünü (kalediaskop) gibi bir film.  Natalie Portman, Fanny Ardant, Elijah Wood, Nick Nolte, Juliette Binoche ve Steve Buschemi gibi, ünlü uluslararası oyuncularla \'Paris, seni seviyorum\'da Paris\'i yeniden keşfedecek; dünyanın bu en romantik şehrine yeniden sevdalanacaksınız.', 6.753, '2006-06-21', 2.6413, 1783119622234, 1783264868402, 1, NULL, 0),
(2, 2280, 0, -1, '[14,18,35]', 'Büyük', '/eWhCDJiwxvx3YXkAFRiHjimnF0j.jpg', '/bi9ihIMB9DoXs7odkS5oKkHoK2o.jpg', 'Tom Hanks\'in 1988 yılında en iyi aktör dalında Oscar® ödülüne aday gösterildiği bu komedi fiminde, Hanks, 30 yaşındaki bir adamın vücuduna sıkışmış 12 yaşındaki bir çocuğu canlandırıyor...  Bir karnavalda genç Josh Baskin (Hanks) büyümeyi diler. Ertesi sabah uyandığında dileğinin gerçekleşmiş olduğunu görür. Arkadaşı Billy\'nin yardımıyla (Jared Rushton), Josh bir oyuncak firmasında işe başlar. Ancak yaşadığı her tecrübeden sonra John çocukluğun sade zevklerini özlemeye başlar...', 7.186, '1988-06-03', 6.1824, 1783119750552, 1783264868402, 1, NULL, 0),
(2, 2288, 0, -1, '[18,10749]', 'Daha Yaklaş', '/vb07BKpNaTmwOvgYT7weol1zdGy.jpg', '/s7oDV92ltdecJ7BTfGSOgsDi900.jpg', 'Günümüz Londra\'sında birbirine yabancı iki çiftten birindeki adamın, diğer çiftteki kadınla tanışmasıyla tesadüfler arka arkaya gelmeye başlar. Birbirlerine duydukları anlık hislerse aldatmaları beraberinde getirir.İngiliz bir gazeteci olan Dan, mesleğini çok ciddiye alan ve kariyer yapmak isteyen biridir. Ancak, onun görevi gazetedeki ölüm ilanları yazmaktır. Dan, genç bir striptizci olan Alice\'ten etkilenir. Ancak, fotoğrafçı Anna\'yla tanışınca, duygularına ve ihtirasına hakim olamaz.', 6.835, '2004-12-03', 15.6072, 1783119541074, 1783264868402, 1, NULL, 0),
(2, 2288, 1, 2, '[10759,80,18]', 'Prison Break', '/wnmNPaLvhnMeOqnWlhNkYCZxtda.jpg', '/n3Brk7roueE9HOwVmYlJx5j462g.jpg', 'Haksız yere suçlandığını düşündüğü abisini hapishaneden kurtarmak isteyen Michael Scofield, nerdeyse kusursuz bir plan yapar. Lincoln Burrows\'a yüklenen suç, kendilerini temize çıkarabilecekleri bir suç değildir. Devletin de işin içine karıştığını öğrendiklerinde kaçmaktan başka çareleri kalmaz. Michael planını uygulamaya sokar ve kaçış başlar.', 8.068, '2005-08-29', 117.1025, 1783056120301, 1783264868402, 1, NULL, 0),
