(3, 2734, 1, 2, '[80,18,9648]', 'Law & Order: Special Victims Unit', '/imaKy0BLfX1iPzj9ZvbOD0D09m6.jpg', '/obtdxPgmfykYwVnvuYXC5f2xKlQ.jpg', 'New York yeraltı dünyasının karanlık yüzünü araştıran bir özel suçlar birimi... New York Polis departmanında cinsel suçlar konusunda uzman dedektiflerden oluşan bu birim, insanın kanını donduran vakaları incelemek zorunda... Her gün yardım isteyen kurbanlar, kapatılmayı bekleyen dosyalarla uğraşan bu ekibin üyeleri, bir yandan da bu araştırmaların özel yaşamlarına olan etkisini dengelemeye çalışıyorlar.', 7.95, '1999-09-20', 274.4824, 1782680053749, 1782680053749, 0, NULL, 0),
(3, 17635, 1, 2, '[10751,18]', 'Aşk-ı Memnu', '/xHulNzEqtgkTuwrRorBRXdGzHML.jpg', '/zcEKO2vdfXAJoAnlgARyhGthLvK.jpg', 'İstanbul\'un sayılı iş adamlarından biri olan Adnan Ziyagil, çok sevdiği eşi İnci öldükten sonra 17 yaşındaki kızı Nihal ve 11 yaşındaki oğlu Bülent ile köşkte bir başına kalır. Çocukların eğitimi için köşke yerleşen Matmazel Deniz de Courton, zaman içerisinde köşkte söz sahibi de olmaya başlar. Matmazel Adnan\'ı yıllarca kendi içinde sevmiş olsa da, Adnan kendisinin yarı yaşında olan Bihter Yöreoğlu’na aşık olur ve onunla evlenir. Önce Bihter bir süre sonra da annesi Firdevs Yöreoğlu köşke yerleşir. Eşini kaybeden Firdevs’in hayattaki tek amacı lüks içindeki yaşamını sürdürebilmektir. Bihter annesine inat uğruna evlendiği Adnan’ı aralarındaki yaş farkına rağmen başlarda sevse de, bir süre sonra Adnan’ın manevi yeğeni hızlı çapkın Behlül Haznedar\'a kapılır. Behlül ise Nihal’in küçüklüğünden beri ona aşık olduğunu anlamamazlıktan gelerek uzatmalı okuduğu üniversitede çapkın yaşamına devam eder; ta ki Bihter’le yasak bir aşkın içine girene kadar...', 6.7, '2008-09-04', 8.4009, 1782681161404, 1782681161404, 0, NULL, 0),
(3, 27275, 0, -1, '[35,12,878]', 'G.O.R.A.', '/bxHULJqeW1GlPWr7uvRoWQWsDIe.jpg', '/g90Hlbaj8OofowG9hDg9ScD5fqG.jpg', 'Arif, Antalya’da halı ticareti yapmaktadır. En büyük zevki UFO’larla ilgili hayaller kurup bunları çevresi ile paylaşmaktır. Bir gün hayali gerçek olur ve uzaylılar tarafından kaçırılır. Komutan Logar’ın esir ettiği Arif, GORA gezegenini bir alev topundan kurtarır. Bu sayede Logar’ın düşmanlığını, Amiral’in kızı Prenses Ceku’nunsa sevgisini kazanır. Oysa Logar, Prenses Ceku ile evlenip gezegeni ele geçirmeyi planlamaktadır. Arif’in yapabileceği tek şey, kaçarken Ceku’yu da yanına almaktır.', 7.3, '2004-11-12', 0.9448, 1782681114150, 1782681114150, 0, NULL, 0),
(3, 30634, 0, -1, '[35]', 'Organize İşler', '/9hydImnaVkVv6PinLMzozFiPP1h.jpg', '/gnyZRWAwdGloChFlJ7OA2YSxt7f.jpg', 'Bir çete lideri, Süpermen kılığındaki intihara meyilli adamı işe alır. Bu sırada çeteyle bağlantılı çalıntı bir arabayı kullanan kadın ise çeteden intikam almayı planlar.', 6.8, '2005-12-22', 0.5132, 1782681118597, 1782681118597, 0, NULL, 0),
(3, 34587, 1, -1, '[10759,18,10768,80]', 'Kurtlar Vadisi', '/yX6JEIijuH6KNCgO8I2yLKu2Psb.jpg', '/sjLv7xpBCP7DZiYS41hMFPRyLQl.jpg', 'Sokaklardan başlayıp belli bir hiyerarşik bütünlük içinde kademe kademe yükselen ve en tepede son derece etkili bir \"konseye\" dönüşerek ülkeyi avcuna almayı amaçlayan çok güçlü bir mafya örgütü ile o örgütle mücadeleye soyunanların serüvenleri anlatılır. Bu hem toplumsal hem de bireysel yansımaları olan bir serüvendir.', 7.3, '2003-01-15', 29.7614, 1782681043196, 1782681043196, 0, NULL, 0),
(3, 34899, 1, -1, '[18,10759]', 'Muhteşem Yüzyıl', '/kryRPZTkCxtIc1bGMjIQgblnPe0.jpg', '/gn8k4ztPnrURIIocMOYdWCFknKJ.jpg', 'Osmanlı İmparatorluğu\'nun XV. padişahı I. Süleyman, yirmi altı yaşında bu büyük iktidarı yönetmeye başladığında,  önüne öyle bir hedef koymuştu ki;  Büyük İskender’den daha güçlü ve yaygın bir dünyada egemenlik kuracak ve Osmanlı’yı yenilmez kılacaktı. Bu yürüyüş ona; batıdaki savaş zaferleri nedeniyle Muhteşem Süleyman, doğuda ise adaletli yönetimine atfen Kanunî Sultan Süleyman ismini kazandıracaktı.', 8.1, '2011-01-06', 25.6222, 1782681047827, 1782681047827, 0, NULL, 0);
INSERT INTO `ratings` (`user_id`, `movie_id`, `is_tv`, `rating`, `genre_ids`, `title`, `poster_path`, `backdrop_path`, `overview`, `vote_average`, `release_date`, `popularity`, `created_at`, `updated_at`, `deleted`, `comment`, `is_spoiler`) VALUES
(3, 39176, 1, -1, '[18,10768,10759,80]', 'Behzat Ç.: Bir Ankara Polisiyesi', '/aRqNQ5v2tvZ9ZRAXpYik0JamHkm.jpg', '/pF1OQe4zaXX9vOwxbxjZzws0CAe.jpg', 'Behzat Ç, 1985 yılında Polis Akademisi\'nden mezun olmuş, cinayet bürosunda görev yapmakta olan bir polistir. Hizmet verdiği süre içerisinde almış olduğu cezalar nedeni ile hep başkomiser olarak kalmıştır. Behzat\'ın eski eşi ile yaşadığı problemler kızına karşı ilgisiz kalmasına sebep olur. Bir süre sonra kızı Berna, intihar eder. Behzat, bu olaydan sonra yıkılır. Behzat Ç. ve ekibinde yer alan polisler Harun, Hayalet, Akbaba, Eda, Selim ve Cevdet, sezon boyunca bir yandan Behzat\'ın kızının ölümü ile ilgili olabilecek kişiler ile ilişki kurarken bir yandan da her bir bölümde yaşanan farklı cinayetlerin çözümü ile uğraşırlar.', 7.753, '2010-09-19', 12.2809, 1782680094688, 1782680129514, 1, NULL, 0),
(3, 48763, 0, -1, '[35]', 'Eyyvah Eyvah', '/cXRQLlxt7FMOySNQhXYRjTKjtEJ.jpg', '/uDFi7xLufT79Ozt0aAMiv88mGea.jpg', 'Büyükannesi ve büyükbabasıyla küçük bir köyde yaşayan klarnetçi İstanbul\'a gitmek zorunda kalır. Burada aniden gelen şöhretin tadını çıkaran bir şarkıcıyla tanışır.', 6.413, '2010-02-26', 0.4012, 1782681119730, 1782681119730, 0, NULL, 0),
(3, 63549, 1, -1, '[35]', 'Kiralık Aşk', '/qrjBau8YQ1xsS7Rire5eJGUNy2g.jpg', '/7l7K63FeW6iUTJZPa6ips71OWDn.jpg', 'Abisi Serdar\'ın borcu için para gerektiğinde kendisini bir aşk oyununda bulan Defne Topal adında genç bir kızın hikâyesidir. Defne, anneannesi Türkan, kız kardeşi Esra ve ağabeyi Serdar ile birlikte yaşamakta ve garson olarak hayatını sürdürmektedir. Annesi ve babası Defne\'yi ve kardeşlerini terk etmiştir. Bir gün Defne\'nin çalıştığı restorana gelen Ömer adındaki iş adamı, yengesinin onun için düzenlediği buluşmadan kurtulmak için aniden Defne\'yi öper. Defne ve Ömer\'in bilmediği şey yengesi Neriman \'ın orada olup öpüştüklerini görmesidir. Bu olaydan sonra Defne\'nin hayatı bir \"teklif\" ile değişir.', 7.433, '2015-06-19', 14.7509, 1782680090958, 1782680130298, 1, NULL, 0),
(3, 65555, 1, -1, '[18]', 'Kara Sevda', '/wCo8QUccl6hBkCzOrm4AaLgc87J.jpg', '/n0lQ50CfQhB8TfB9hzpeBrJBZ6L.jpg', 'Kara Sevda, 14 Ekim 2015\'te Star TV\'de yayınlanmaya başlayan yeni dizidir. Dizinin başrollerinde Burak Özçivit, Neslihan Atagül ve Kaan Urgancıoğlu yer almaktadır. Yapımcılığını Kerem Çatay\'ın üstlendiği dizinin yönetmen koltuğunda Hilal Saral bulunmaktadır. Senarist kadrosunda Anıl Eke, Özlem Yılmaz ve Burcu Görgün\'ün bulunduğu dizinin oyuncu kadrosunda ayrıca; Kürşat Alnıaçık,Burak Sergen Zeyno Eracar, Orhan Güner, Neşe Baykent, Barış Alpaykut, Melisa Aslı Pamuk yer alıyor. Dizinin çekimleri 1. bölümdeki maden kazası(Zonguldak) hariç İstanbul ilinde gerçekleşmektedir. Dizide madende bir facia yaşandıktan sonra hayatı değişen genç bir maden mühendisinin hikayesi anlatılmaktadır. Genç madenciyi Burak Özçivit canlandırıyor.', 7.841, '2015-10-14', 15.7781, 1782680086477, 1782680131039, 1, NULL, 0),
(3, 68569, 1, -1, '[10751,18]', 'Anne', '/kRYBwumE4hNK4JnHNcU8hRIiDSd.jpg', '/mZD8Y1qlVUY7kwExzdUgZXjiyOK.jpg', '7 yaşındaki Melek, pavyonda çalışan annesi Şule ve onun zalim sevgilisi Cengiz\'le aynı evde yaşamakta ve sistemli olarak dayak ve işkenceye maruz kalmaktadır. Minik kız ne yaşarsa yaşasın minik tavşanı Pamuk\'la ve hayal ettiklerini yazdığı defterle mutlu olmaya çalışmakta ve bir gün hayatının tamamen değişeceğine inanarak hayaller kurmaktan hiç vazgeçmemektedir. Yeterince beslenemediği için çok çelimsiz ve bakımsız görünen minik Melek ile Zeynep arasında çok özel bir bağ kurulur. Zeynep aslında turna kuşlarını fotoğraflayan, soğuk duruşlu, duygularını pek belli etmeyen bir fotoğraf sanatçısıdır. Bir üniversiteye proje sunmuş ve onun onaylanmasını beklerken de geçici olarak okulda ücretli öğretmenlik yapmaya başlamıştır. Kız kardeşleri ve annesi ile 10 yıldır görüşmüyordur. Melek\'in son olarak ölüme terk edilmesi Zeynep\'in bütün gelecek planlarını değiştirmesine neden olur.', 8.092, '2016-10-25', 15.5694, 1782680088426, 1782680130913, 1, NULL, 0),
(3, 70798, 1, -1, '[18,10751,35]', 'İstanbullu Gelin', '/alVrRNxDGOlULYdXgnOpPrVP7KL.jpg', '/raosbKSonz7ZkuZsfxHG5LgH0Wl.jpg', 'Annesiz babasız büyümüş, genç yaşta hayatın yükünü sırtlamış, çok güzel ve gururlu bir genç kız olan Süreyya’nın, karizmatik iş adamı Faruk’a aşık olup Bursa’ya gelin gitmesiyle başlayan hikayesi.', 7.4, '2017-03-03', 19.1395, 1782681053539, 1782681053539, 0, NULL, 0),
(3, 74823, 1, 2, '[80,10759,18]', 'Çukur', '/7aL9P5NLSgBjdChcwp4cH1OLdKf.jpg', '/xtCzLQOocIajjQ5Mhwp834BQhVX.jpg', 'İstanbul’un en belalı mahallerinden Çukur’un kontrolü Koçova ailesinin elindedir. Koçovalıların Çukur’u yönetirken en önemli kuralları da uyuşturucuya asla izin vermemeleridir. Ancak gözünü bu mahalleye dikmiş ve bu yasağı kırmaya hazırlanan yeni bir grubun ortaya çıkması ile mevcut düzen bozulur.', 7.6, '2017-10-23', 79.3128, 1782680995878, 1782680995878, 0, NULL, 0),
(3, 77532, 1, 3, '[18]', 'Kadın', '/nGW4STJLVazkq41RcFa7kGe12qI.jpg', '/87jtXEQrDGgRTbbYiDvqYWcOFWp.jpg', 'Kocası Sarp’ın ölümünden sonra Bahar’ı hayata bağlayan iki şey vardır: Çocukları Nisan (7) ve Doruk (4). Onlarla elele verip hayatı bir oyuna, fakirliği eğlenceye, yokluğu neşeye çevirmeyi başarır. İnsanın yüzü güldüğünde kalbinin de onunla birlikte gülümseyeceğine inanır.', 7.588, '2017-10-24', 6.9721, 1782681768181, 1782681768181, 0, NULL, 0),
(3, 80411, 1, -1, '[18,35,10766]', 'Erkenci Kuş', '/rGjYq9bi5jpAMZTJnou1UNpmKWj.jpg', '/uJ3HalVLkaOeH1lvDdrEmeqFxds.jpg', 'Sanem sabahları birkaç saat babasının bakkalında çalıştıktan sonra bütün gününü hayal kurarak ve kitabı üzerinde çalışarak geçirmektedir ve hayatından son derece mutludur. Ta ki anne babası kendisine doğru düzgün bir iş bulmazsa evlenmek zorunda olduğunu söyleyene kadar! Sanem bunun üzerine mecburen ablasının iş yerinde çalışmaya başlar. Hayallerini süsleyen büyük aşkının kendisini orada beklediğinden habersizdir henüz, üstelik bilmeden Can\'a ve şirkete kurulan bir tuzağın parçası olur... Yalanlar üzerine kurulan bir aşk olabilir mi? Ya Sanem? Nefret ettiği Can\'a kalbini kaptırabilir mi?', 8.1, '2018-06-26', 16.3963, 1782680085529, 1782680131230, 1, NULL, 0),
(3, 82328, 1, -1, '[10751,18]', 'Bir Zamanlar Çukurova', '/ayRjBKyBXzKGHajgVGsiMiK5THy.jpg', '/8vXYq2l38DsPzGD8lpokinZiPuV.jpg', 'Dizide aşkı için öldürmeyi göze almış Yılmaz ile sevgilisi yaşasın diye kendini istemediği bir adamla yaptığı evliliğe hapseden Züleyha\'nın hikayesi anlatılıyor. Ama bu hikayede sadece ayrı düşen iki sevgili yok! Ailesinin görkemli geçmişini ve biricik oğlunu korumak için kanatlarını açmış bir Hünkâr\'ın savaşı da var; aşık olduğu kadını tutsak etmeyi göze alan Demir de! Ve elbette sınırsız aşkların coğrafyasında, geçmişten bugüne uzanan hesaplaşmalar, paylaşılamayan topraklar da! Aşkın sınırsız, kavganın ölümüne, umudun inadına yaşandığı Çukurova\'da ihtiras ve zorbalık sınavlarından geçen bir aşkın hikayesi.', 7.741, '2018-09-13', 11.6168, 1782680097237, 1782680128815, 1, NULL, 0),
(3, 82452, 1, 0, '[10759,10765,18,10751]', 'Avatar: The Last Airbender', '/lzZpWEaqzP0qVA5nkCc5ASbNcSy.jpg', '/xUB3xFMgsHgPmdWnUWkHTJ03vHa.jpg', 'Avatar olarak bilinen bir çocuk, savaş hâlindeki dünyayı kurtarmak için dört element gücünde de ustalaşmalı ve onu durdurmaya kararlı olan acımasız bir düşmanla savaşmalıdır.', 7.804, '2024-02-22', 286.8657, 1782995259803, 1782995259803, 0, NULL, 0),
(3, 87623, 1, -1, '[18]', 'Hercai', '/xDHKKIQrwL3vP3BKov5TeBTzvRD.jpg', '/pcZUSUH31odGlq41XktxLVmjNSm.jpg', 'Midyat\'ın en güçlü ailelerinden Şadoğullarının torunlarından biri olan Reyyan ile yıllar önce öldürülen anne babasının intikamını almak isteyen Miran\'ın imkansız aşk hikayesi.', 7.754, '2019-03-15', 11.662, 1782680096288, 1782680129151, 1, NULL, 0),
(3, 92967, 1, -1, '[18]', 'Mucize Doktor', '/ZNxfeXYnlUGYk1cMzL7CBvUnHs.jpg', '/j9orEeA4twmIEQtHdaAW0L1L7nE.jpg', 'Savant sendromlu deha Ali Vefa’nın en büyük hayali doktor olmaktır. Engeline ve karşılaştığı bütün önyargılara rağmen tıp fakültesini bitirmiş, stajını tamamlamış ve geriye sadece ihtisas yapmak kalmıştır. Yaşadığı taşra şehrinden ayrılır ve manevi babası Adil Erinç’in Başhekimi olduğu İstanbul Berhayat Hastanesi’nde Cerrahi Bölüm Asistanı olarak işe başlamak üzere yola çıkar. Ama havaalanında meydana gelen bir kaza Ali’yi hayatının en önemli toplantısına geç bırakır. Aynı sıralarda hastane yönetim kurulu toplanmış, Ali’nin işe alınıp alınmayacağını tartışmaktadır. Adil hariç kimse otizmli birinin doktor olabileceğine inanmaz. Ve Ali, saatlerce geç kalarak, korka korka, kendisine acımayla, inançsızlıkla bakan yönetim kurulunun karşısına çıkar… Önyargılar kırılabilir mi? Hayaller gerçek olabilir mi?', 8.068, '2019-09-12', 13.341, 1782681765449, 1782681765449, 0, NULL, 0),
(3, 94997, 1, 1, '[10765,18,10759]', 'House of the Dragon', '/6YM292PX2gSIBk16hufmlGT3iQW.jpg', '/h37hqVLmCW00ImewLAHT1DadOky.jpg', 'George R.R. Martin\'in \"Fire & Blood\" adlı eserinden uyarlanan ve Game of Thrones\'taki olaylardan 200 yıl öncesini konu alan dizi, Targaryen Hanesi\'nin gücünün zirvesinde olduğu dönemde bir iç veraset savaşını anlatıyor.', 8.3, '2022-08-21', 480.817, 1782678158425, 1782678158425, 0, NULL, 0),
(3, 95603, 1, -1, '[10768,10759,18]', 'Kuruluş: Osman', '/rQUhcrcvWoPHjxRc6hzlD2enmRK.jpg', '/puLaqdcTRwFxwv9S3PO6jA3ep7J.jpg', 'Dizi, Ertuğrul Gazi\'nin oğlu ve Osmanlı İmparatorluğu\'nun kurucusu Osman Bey\'in hayatına odaklanacak.', 7.917, '2019-11-20', 61.5612, 1782681014832, 1782681014832, 0, NULL, 0),
(3, 96348, 1, -1, '[9648,18,10765]', 'Atiye', '/23hcx6YvPrmEgQWAA0ZFyXL9jh3.jpg', '/tOvVG4uigMTTZiZdUeNMd1BA22U.jpg', 'Atiye, genç ve güzel bir ressamdır. Ailesi ve sevgilisi Ozan’la mutlu bir hayatı olan Atiye, dünyanın en eski tapınaklarından olan Göbeklitepe’ye bir ziyaret gerçekleştirir. Atiye’nin bölgede yaptığı gezi sırdasında, Erhan adındaki bir arkeolog, Atiye ile Göbeklitepe arasında mistik bir bağlantı olduğuna dair bir sembol keşfeder. Bu olayın peşini bırakmayan ve irdelemeye başlayan Atiye, geçmişin izlerini de bulmaya çalışır ve kendisine bambaşka bir yol çizer. Atiye, geçmişi kovaladıkça ve yeni detaylara ulaştıkça, geçmişle geleceği, gerçek ile ruhani olayları birbirinden ayırt edememeye başlar.', 7.344, '2019-12-27', 4.4173, 1782681079922, 1782681079922, 0, NULL, 0),
(3, 100868, 1, -1, '[18,10751,10766]', 'Emanet', '/wmyqaUTyfEuOBi6uy0Wvw9i3dVH.jpg', '/dOpHCDo2bCQIrrnuofKkZExMo3G.jpg', 'Zengin ve karizmatik bir iş adamı olan Yaman Kırımlı ile masum ve mütevazı bir hayatı olan Seher Kerimoğlu\'nun hikâyesini içeren dizide hem Yaman hem de Seher ailesini kaybeden ve kendilerinden başka bir yakını olmayan yeğenleri Yusuf\'u emanet olarak görmektedir. Yaman Kırımlı çok zengin bir adamdır ama geçmişte yaşadığı zor günlerin etkisinden bir türlü kurtulamaz. İki ağabeyi olan Yaman, onları terk ederek başka bir adamla giden annesini hiç affetmez. Annesinin evi terk etmesiyle intihar eden babasını ise bir türlü unutamaz. Yaman Kırımlı bu durumdan sonra kadınlardan nefret eder ve hiçbir kadına güvenmemektedir. Yaman yeğeni Yusuf\'u da acımasız ve güçlü biri olarak yetiştirmek ister Seher ise emanet olarak gördüğü yeğenini almak ve onu kendi istediği gibi yetiştirmek ister. Tabi Yaman Kırımlı buna asla izin vermeyecektir. Seher ise Yaman\'ın tüm zorluklarına rağmen yeğenini almak ister ve bu konu da her şeyi göze alacaktır.', 7.651, '2020-09-07', 22.4652, 1782681049891, 1782681049891, 0, NULL, 0),
(3, 100897, 1, -1, '[35,18]', 'Aşk 101', '/l6pLzAgUU2QpJ6KlsReqSqwWnfa.jpg', '/uxxr14xvFgpGDdTAoLJJFsAZYSB.jpg', 'Öğretmenlerinin bir basketbol koçuna âşık olmasını sağlamaya çalışan dört isyankâr ve bir örnek öğrenci, birlikte arkadaşlığı, aşkı ve kendileri olma cesaretini öğrenir.', 7.749, '2020-04-24', 4.3829, 1782681080905, 1782681080905, 0, NULL, 0),
(3, 104877, 1, -1, '[18,35]', 'Sen Çal Kapımı', '/nzBenFJ2D2MCWTwTt2uc4BGWLtA.jpg', '/9qq8LpOoBLYq8MxiMugn0gf9qJd.jpg', 'Sen Çal Kapımı dizisinde, hayatta bütün umutlarını eğitimine bağlayan Eda Yıldız, yurt dışı eğitim bursunu keserek lise mezunu kalmasına neden olan Serkan Bolat ile karşı karşıya gelir. Serkan Bolat, Eda’ya kendisiyle iki ay nişanlı taklidi yaparsa, bursunu geri vermeyi teklif eder. Eda nefret ettiği bu adamın teklifini önce reddetse de koşullar değişince kabul etmek zorunda kalır. Nişanlı taklidi yaparken, Serkan ve Eda, bütün doğru bildiklerini unutturacak, tutkulu, zorlu bir ilişki yaşamaya başlayacaktır.', 8.223, '2020-07-08', 30.9707, 1782681041214, 1782681041214, 0, NULL, 0),
(3, 110562, 1, -1, '[18]', 'Sadakatsiz', '/47tPvMrNzquyC9GTrELfX9vRQNm.jpg', '/76aveobsWhFYon5DHP7CAjo9GYJ.jpg', 'Asya, başarılı bir doktordur. Kocası Volkan, harika bir eş ve oğulları Ali’ye şahane bir babadır. Üç kişilik çekirdek aile, hep huzur ve mutluluk dolu bir hayat yaşamışlardır... Beyaz güller kadar saf bir ilişkidir Asya’nın gözünde yıllardır süren evlilikleri... Ta ki; Asya, Volkan’ın atkısındaki sarı uzun saç telini görene dek…', 8.068, '2020-10-07', 15.1584, 1782680089558, 1782680130637, 1, NULL, 0),
(3, 112745, 1, -1, '[18,9648]', 'Bir Başkadır', '/9MzukREEyaCqW197buBrJr2LcTI.jpg', '/peOoKDVMbXdBMwZd9SeOxtOfCXD.jpg', 'Dizi, birbirlerinden oldukça farklı karakterde olan ve bambaşka hayatlar yaşayan bir grup insanın yollarının kesişmesiyle değişen yaşamlarını konu ediyor. Bu karakterler ya yeni bir yola yürümek ya da karmaşık bir geçmişle hesaplaşmak zorunda kalacaklardır.', 7.744, '2020-11-12', 2.5727, 1782681088783, 1782681088783, 0, NULL, 0),
(3, 115678, 1, -1, '[35]', 'Gibi', '/sOzTUfTc1djfZM46PgsjuOjs5U1.jpg', '/p7VgbdDN2LK41JTavzJ9x3i4ktE.jpg', 'Yılmaz, İlkkan ve Ersoy... Sürekli olarak birbiriyle didişmekte olan üç arkadaş. En büyük özellikleri ise sıradan hayatlarını altüst edecek bir şeyler yapmayı her zaman becermek. Küçücük olayları inanılmaz bir ustalıkla büyütüyor, işleri saç baş yolduracak seviyeye getiriyorlar. Onlar her gün yaşadığımız talihsizliklerin, tuhaf olayların ve çaresizliklerin cisimleşmiş hali.', 8.577, '2021-01-01', 13.5414, 1782680092157, 1782680129927, 1, NULL, 0),
(3, 115970, 1, -1, '[80,9648]', '50M²', '/3m0aiNtGZo6URftj88zGIrsv0V2.jpg', '/1aZ7AmKU92ihCzge0eNdNtZ7icg.jpg', 'Karanlık bir adamın kirli işlerini yapan Gölge, geçmişine ait sır perdesini aralamaya çalışırken işler karışır ve kendini bambaşka bir kimlikle küçük bir mahallede bulur.', 7.4, '2021-01-27', 2.1491, 1782681092847, 1782681092847, 0, NULL, 0),
(3, 123138, 1, -1, '[80,18]', 'Fatma', '/sbfgYpPYfTC2j1EU0l3SsyPUaIt.jpg', '/wbrASNjkv8bOef9dnu1Bk3PdY0E.jpg', 'Temizlik işlerine giden Fatma, kayıp eşi Zafer’i ararken beklenmedik bir kaosun içine çekilir. Fatma kimsenin şüphelenmediği görünmez bir “temizlikçi” olduğunu fark eder.', 6.9, '2021-04-27', 2.2426, 1782681090349, 1782681090349, 0, NULL, 0),
(3, 124364, 1, 2, '[9648,18,10765]', 'FROM', '/pRtJagIxpfODzzb0T0NAvZSzErC.jpg', '/m7eiSGHFzr584zFmetGqkqaU6BN.jpg', 'Amerika Birleşik Devletleri\'nin ortasındaki kabus gibi bir şehir, içine giren herkesi tuzağa düşürür. Kasaba sakinleri, normallik duygusunu sürdürmek ve bir çıkış yolu aramak için savaşırken, güneş battığında ortaya çıkan korkunç yaratıklar da dahil olmak üzere, çevredeki ormandan gelen tehditlere karşı da hayatta kalmak için çabalar.', 8.494, '2022-02-20', 706.0003, 1782678152830, 1782678152830, 0, NULL, 0),
(3, 136125, 1, -1, '[18]', 'Kulüp', '/jHgMj6mtMHEBrFhmZaQCGFGYnFx.jpg', '/AwEQ9wAOs1ZbvhpO7XxpGQHYvx5.jpg', '1950\'lerin kozmopolit İstanbul\'unda bir anne, sorunlu geçmişi yüzünden yetiştiremediği asi kızıyla yeniden bağ kurmak için bir gece kulübünde çalışmaya başlar.', 6.845, '2021-11-05', 2.8727, 1782681085352, 1782681085352, 0, NULL, 0),
(3, 157219, 1, -1, '[18,9648,80]', 'Pera Palas’ta Gece Yarısı', '/uslNVfFRXnY4I8J6yohGatDUs30.jpg', '/n5MXQXuj5RnpZcxvDtO4sgzcKaY.jpg', 'Tarihî Pera Palas Oteli ile ilgili bir yazı hazırlarken kendini bir anda geçmişte bulan gazeteci Esra, Türkiye\'nin kaderini değiştirebilecek bir komployu durdurmalıdır.', 7.6, '2022-03-03', 3.9521, 1782681082720, 1782681082720, 0, NULL, 0),
(3, 195930, 1, -1, '[10765,18]', 'Yakamoz S-245', '/nPeoZkjQRtrQh3IDaxlM6KQg9NL.jpg', '/eJjM0s1YIsf9CtIQTIb81tl1I4I.jpg', 'Dalış eğitmeni ve deniz biyoloğu olan Arman, yaşanan bir doğa felaketinin ardından araştırma yapmak için bilim ekibiyle birlikte bir askeri denizaltısına biner. Yaşananları anlamaya çalışan Arman ve ekibi, aynı zamanda askeri denizaltının da gerçek görevinin ne olduğunu öğrenmeye çalışır. Arman, kendini, ekibini ve tahmin ettiklerinden de daha fazlasını kurtarmaya çalıştığı bu süreçte başarılı olabilecek midir?', 6.7, '2022-04-20', 2.6467, 1782681086867, 1782681086867, 0, NULL, 0),
(3, 197679, 1, -1, '[35]', 'Erşan Kuneri', '/8T40UoCYztenuMOGLSTdch903k4.jpg', '/e9iztxikysYdbx3gwGrMt05kFWV.jpg', '70\'ler erotik sinemasında büyük bir başarı yakalayan Erşan Kuneri, farklı türlere de el atmaya karar verir. Kuneri, sektörden partnerleri olan Alev, Altın Oran, Miki Muammer, Seyyal, Kaya Akın, Firdevs ve Payro Kemal ile birlikte farklı film türlerini denemek için harekete geçer.', 6.731, '2022-05-13', 3.8835, 1782681083553, 1782681083553, 0, NULL, 0),
(3, 202010, 1, -1, '[18]', 'Kuş Uçuşu', '/7PPVzg636s6Q15PYdr7HhkNQg9o.jpg', '/opHnAwvV1XY2EgR7gScAv2cdjMg.jpg', 'Bakış açıları, yaklaşımlar ve hedefe giden yolda yürüme biçimleri X kuşağına göre artık bambaşkadır. Genç bir kadın olan Aslı da kariyer basamaklarını tırmanmak için çok çalışmaya güvenmek yerine \'kuş uçuşu\' gitmeye çalışır. Yeni dünyanın yöntemleriyle en üste ulaşmaya çalışan Aslı amacına ulaşabilecek midir?', 7, '2022-06-03', 4.2964, 1782681081771, 1782681081771, 0, NULL, 0),
(3, 206180, 1, -1, '[18]', 'Zeytin Ağacı', '/p2UqCeIEdDqq0MTR8HwGEfZfu6J.jpg', '/eND0QkFMyqWONmAy1lBKtPjsrFF.jpg', 'Ada, Sevgi ve Leyla\'nın “rakı, balık, Ayvalık” olarak başlayan macerası, onları geçmişleriyle barıştırırken kendi yaşamları için yepyeni kararlar almalarını sağlar.', 7.8, '2022-07-28', 35.5058, 1782681035967, 1782681035967, 0, NULL, 0),
(3, 210865, 1, -1, '[10751,18]', 'Yalı Çapkını', '/pzDHrbX7780TcNrV4P7j5xrgE6u.jpg', '/vDqCoaMU5FUAuUs0EvL4OAUCxJk.jpg', 'Yalı Çapkını, Gaziantepli Korhan Ailesi\'nin direği Halis Ağa\'nın (Çetin Tekindor) el bebek gül bebek yetiştirilmiş torunu Ferit\'in (Mert Ramazan Demir) evlenmesine karar vermesiyle gelişecek olayları konu alıyor.', 8.295, '2022-09-23', 51.9672, 1782681032686, 1782681032686, 0, NULL, 0),
(3, 212818, 1, -1, '[18,9648,10765]', 'Sıcak Kafa', '/dt1RGQTZs1wqywXSdygWU62zCmX.jpg', '/3ki76LOS8nXo8GcM03i0jiwZvGI.jpg', 'Dünya gizemli bir salgının etkisi altındadır. Dil ve konuşma yoluyla yayılan bu salgından sadece eski bir dil bilimci olan Murat Siyavuş etkilenmez. Salgınla Mücadele Kurumu, hastalıktan kurtulan tek kişi olan Murat\'ın peşine düşünce genç adam, saklandığı kurtarılmış bölgeden çıkmak zorunda kalır. Korunaklı alanından çıkan Murat Siyavuş, salgının etkisi altına aldığı İstanbul\'un gizemli yerlerinde hastalığın mirası olan “sıcak kafa”sının sırrını ortaya çıkarmak için zorlu bir mücadeleye girişir.', 5.949, '2022-12-02', 2.9035, 1782681084518, 1782681084518, 0, NULL, 0),
(3, 214078, 1, -1, '[18,10765,9648,10759]', 'Şahmaran', '/1fKsga4dTxTRNFp1ktUWUa7P1Ib.jpg', '/bkdZHK0Nh1YaRXkk2j8vUGYQd6i.jpg', 'Şahsu, öğretim görevlisi olarak gittiği Adana’da yıllar önce annesini terk eden büyükbabasıyla yüzleşmeye kararlıdır. Bu yolculukta kendisini Şahmaran’ın soyundan gelen ve Mar adı verilen sıradışı ve gizemli bir topluluğun ortasında bulur. Aşkın ve bilgeliğin en büyük sembollerinden olan Şahmaran efsanesine inanan Mar ırkı, Şahsu’nun da gelmesiyle tarihi kehanetin tamamlanmasını beklemektedir. Büyükbabasından geçmişin hesabını sormak üzere yola çıkan Şahsu’nun Maran ile yollarının kesişmesiyle bir daha hiçbir şey eskisi gibi olmayacaktır…', 6.71, '2023-01-20', 5.3402, 1782681077840, 1782681077840, 0, NULL, 0),
(3, 214079, 1, -1, '[18,9648]', 'Terzi', '/i8YLOXlSJoBfG2cvaZQyu58Z9Fg.jpg', '/5vaDrDaJij9JFF7cwrJvAMypxLY.jpg', 'Ünlü terzi Peyami, en iyi dostunun müstakbel eşi için gelinlik dikmektedir. Ama hiç görmediği bu kız beklenmedik şekilde hayatına girince, Peyami’nin sırlarına bir yenisi eklenir.', 7.34, '2023-05-02', 4.9332, 1782681078956, 1782681078956, 0, NULL, 0),
(3, 214081, 1, -1, '[18,10765]', 'Yaratılan', '/kINoiBSOfHHVmNwJ4i766j93RR1.jpg', '/6kC51Z17J5h7rLEokyud4bojPyr.jpg', '1900’lü yılların başında maceraperest, asi, heyecanlı ve zekası bedenine sığmayan genç tıp talebesi Ziya’nın en büyük dileği, çok iyi bir hekim olup tıbbın çare bulamadığı birçok salgın hastalığa derman olabilmektir. İstanbul’da tanıştığı delilik ve dahilik arasında duran hekim İhsan, onu bu dünyada anlayabilen tek kişi olmuştur. Birbirini bulan bu iki eksantrik ve yaralı ruh, beraber giriştikleri gizli ve yasaklı deneyin bedellerini ağır bir şekilde ödeyeceklerdir. Zira kodlarını çözmeye çalıştıkları kadim bir yazı onları adeta felaketin kapısına getirip bırakır.', 7, '2023-10-20', 1.6247, 1782681095829, 1782681095829, 0, NULL, 0),
(3, 219064, 1, -1, '[80,9648,18]', 'Biz Kimden Kaçıyorduk Anne?', '/ve0Yu4SGfLkmk9wx4tIgfkDX0uP.jpg', '/j9eZYlyoNwYpI5GxysDWoOOSXUn.jpg', 'Bir anne ve küçük kızı Bambi, hayatlarını sürekli birilerinden kaçarak sürdürür. Lüks otellerde yaşayan anne ve kız, arkalarında sadece cesetlerden izler bırakarak yollarına devam eder. Ancak bir süre sonra lüks oteller yerini motele bırakır ve böylece peri masalının söz verildiği gibi olmayacağı ortaya çıkar.', 6.649, '2023-03-24', 2.1701, 1782681091448, 1782681091448, 0, NULL, 0),
(3, 231503, 1, -1, '[18]', 'Yabani', '/lQ5k6i7Bv3ssV4uotxZpTdKCgC9.jpg', '/897uYgM4gtY0MdPRszIJngRJrIp.jpg', 'Köklü bir aileden kaçırılıp sokaklara düşen bir çocuğun, yıllar sonra evine dönmesi ile kendini yeniden var etme mücadelesini anlatıyor.', 8.654, '2023-09-12', 35.51, 1782681033918, 1782681033918, 0, NULL, 0),
(3, 273240, 1, 1, '[18]', 'Off Campus', '/cbODFqkcmRgrYH8NkG4Q4Hcg8Z1.jpg', '/52sp0vPhLOWrZ1QoZIWiapronM.jpg', 'Hannah Wells, hokey kaptanı Garrett Graham\'a, hoşlandığı kızı kazanması için ders verir. Anlaşmaları, geçmişleriyle yüzleştikçe yakınlaşmaya dönüşür. Logan, Dean, Tucker ve Allie adlı arkadaşlar, üniversite hayatı ve aşkı keşfederler.', 8.955, '2026-05-13', 305.824, 1782678200064, 1782678200064, 0, NULL, 0),
(3, 276880, 1, 3, '[16,35]', '履いてください、鷹峰さん', '/aFidY5oV5z5Fm8gPh37IYyBjbhG.jpg', '/5AYXcPhbtPe6i1MPnutPhCV6qNd.jpg', '', 7.5, '2025-04-02', 550.9895, 1782678155111, 1782678155111, 0, NULL, 0),
(3, 284631, 1, 2, '[80,18]', 'Karanlığın Kalbi', '/5MbNy94ia4ZLf8OGtSfSjjlxxWN.jpg', '/hAuYDYBgLJ1qIPoAOM7yOD56uCp.jpg', 'Karanlığın Kalbi, Delhi\'de iki gencin kaybolması ve öldürülmesiyle başlayan tüyler ürpertici bir suç dizisi. 1970\'lerin sonlarında, bu tür vahşetin nadir ve şoke edici olduğu bir dönemde geçen dizi, katilleri bulmak için başlatılan amansız bir insan avını izlerken suçun arkasındaki adamların rahatsız edici psikolojisini de inceler.', 9.2, '2026-06-12', 352.5378, 1782678161056, 1782678161056, 0, NULL, 0),
(3, 295748, 0, -1, '[35,18,10749]', 'Pek Yakında', '/qf2lRjHMZMQuYY7MR4oa6abgvrD.jpg', '/kzj8i8vgXScxtINrdufHQ39A1w6.jpg', 'Hayatını korsan DVD\'cilik ve beraberindeki birtakım kanunsuz işlerle kazanan Zafer, bir gün karısından büyük bir posta yer ve anlar ki bu işleri bırakmazsa evliliği bitecekir. Kanunsuz işlere zinhar tövbe eden Zafer, ailesini geri kazanmak için figüranlık yaptığı eski \'oyunculuk\' günlerine geri döner. Amacı o günlerden gelen sinemacı dostlarıyla yeniden bir ekip oluşturmak ve 1970’lerden beri çekilememiş fantastik bir proje olan “Şahikalar-Kötülüğün Sonu” adlı filmi içekmektir. Fakat kurduğun ekibin yetenekleri de bir noktada gelir takılır. Şimdi hepsini eğlenceli, komik ve bir o kadar da duygusal bir macera bekler.', 6.643, '2014-10-02', 0.6095, 1782681118111, 1782681118111, 0, NULL, 0),
(3, 366759, 0, -1, '[12,28,35]', 'Ali Baba ve 7 Cüceler', '/x5o8vK2BJlXU8qtgNoNNIObJ1rw.jpg', '/gVs4zFnqpKyrqvYpYU4vdDAJiJ.jpg', 'Bahçe cüceleri satan Şenay Cüccaciye\'nin sahibi olan Ali Şenay ve İlber işlerini büyütüp dünyaya açılmak için Sofya\'da bir fuara katılır. Fuarda işler istedikleri gibi gitmeyince başları belaya girer. Mançov adlı kötü kalpli bir adamın plânlarından haberdar olan Şenay ve İlber, onun hain plânlarını durdurabilmek için yeni tanıştıkları Memedov ve Veronika ile büyük bir mücadeleye girişir.', 4.933, '2015-11-12', 0.4202, 1782681118755, 1782681118755, 0, NULL, 0),
(3, 472454, 0, -1, '[18,10752,36]', 'Ayla', '/ggtQgembIFKJcSSeuxJocOklasp.jpg', '/6EbxuGgAjizKqd9CmG5HG0m0t23.jpg', '1950 yılında Kuzey Kore, Güney Kore\' ye saldırdığında Birleşmiş Milletler\' in yaptığı yardım çağrısı sonucu Türkiye, Kore\'ye bir tugay gönderir. Her şey gönderilen tugayın içindeki askerlerden birisi olan Süleyman Astsubay\'ın savaş meydanında annesi babası öldürülmüş küçük bir kız bulmasıyla başlar. Süleyman Astsubay bulduğu 5 yaşındaki küçük kıza ay gibi yüzü olduğu için Ayla ismini verir. 15 ay boyunca Ayla\'nın bakımını üstlenen Süleyman Astsubay\'ın artık Türkiye\' ye dönmesi gerekmektedir. Ayla\'yı bırakıp gitmek istemeyen Süleyman, Ayla\'yı Türkiye\'ye götürmek için birçok yolu dener ancak bir türlü Kore yasalarını aşıp Ayla\'yı Türkiye\'ye dönerken yanına alamaz. Savaş günlerini geride bıraktıktan 60 yıl sonra Ayla ve Süleyman tekrar bir araya gelirler.', 8, '2017-10-27', 2.601, 1782681087733, 1782681087733, 0, NULL, 0),
(3, 477313, 0, -1, '[35]', 'Aile Arasında', '/lxA6UjZqRX1LFCQ6kgjpbCCP3JI.jpg', '/xTAEtKYzlgTJJgCJ6XTjJWznTs0.jpg', '21 yıllık eşinin aniden terk ettiği Fikret ve 21 yıllık müzisyen sevgilisi tarafından terk edilen müzikhol vokalisti Solmaz komik bir tesadüfle tanışması ve dost olmasının ardından Solmaz\'ın kızı Zeynep, bu sırada ailesiyle ilgili yalanlar söylediği Adanalı sevgilisinden evlenme teklifi alır. Solmaz, Fikret\'ten, kızının saygın, efendi, emniyet müdürü babası rolünü oynamasını ister. Aile arasında bir kız isteme, bir de düğün olacak ve bu iş bitecektir. Ancak damadın geleneklere bağlı olan ailesi detaylı evlilik seremonileri planlamaktadır. Asla yalan söyleyemeyen, nevrotik ve tedirgin bir insan olan Fikret, sert, silah taşıyan ve kebapçı zinciri sahibi bir Adanalı aileye karşı hayatının rolünü oynamak zorundadır.', 6.7, '2017-12-01', 0.8413, 1782681115916, 1782681115916, 0, NULL, 0),
(3, 499461, 0, -1, '[35,28,80]', 'Ölümlü Dünya', '/6pUboTFJ6SNzrhb8sNcmc50fJCk.jpg', '/6V9AbZvuHi4vEFSnLMr1NnGCzic.jpg', 'Nesillerdir Haydarpaşa Garı\'nda Anadolu Tat Lokantası\'nı işleten Mermer Ailesi, sekiz kişiden oluşan geniş bir ailedir. Kendi halinde, sade bir yaşamları olan bu insanların durumları biraz karışıktır. Bu ailenin, uzun zamandır gizledikleri bir de sırları vardır. Bu sır, her ne pahasına olursa olsun açığa çıkmaması gerekmektedir.', 7.1, '2018-01-26', 0.6405, 1782681117962, 1782681117962, 0, NULL, 0),
(3, 577990, 0, -1, '[35,80,28]', 'Organize İşler: Sazan Sarmalı', '/p5vsOFlPOfdBEXSgrW9fcxdfJNC.jpg', '/sGPoP2RYLifBh9ZYFVn2H74r9RW.jpg', 'Kızı ve damadı bir dolandırıcılık kurbanı olduğunda, İstanbullu üçkâğıtçı Asım Noyan yasa dışı bahis dünyasından deli fişek bir patronla karşı karşıya gelir.', 5.587, '2019-02-01', 0.6495, 1782681117539, 1782681117539, 0, NULL, 0),
(3, 637920, 0, -1, '[18]', '7. Koğuştaki Mucize', '/sOfUbzu6OUL5cscGODPdpHn9C1g.jpg', '/inEy3A5OPgeYW4rjRiGycfEeQzA.jpg', 'Darbe döneminde bir Ege kasabasında, canından çok sevdiği küçük kızı ve babaannesiyle birlikte yaşayan Memo, mental yetersizliği olan ama küçük dünyasında mutlu yaşayan bir çobandır. 1983 yılında bir gün, sıkıyönetim komutanının kızının ölümü üzerine kalan ve sıradan hayatı birden altüst olan Memo, idam cezasına çarptırılır ve böylece ‘Yedinci Koğuş’a gelir. Burada hayatta kalması pek mümkün görünmemektedir. Fakat başta onu nefretle karşılayan tüm koğuş, onun iyilik dolu kalbini görür, yavaş yavaş Memo’nun cinayet işleyebilecek bir kişiliği olmadığına ikna olmaya başlar ve zamanla hayatına dokunduğu herkes Memo’nun hayatını kurtarmak için seferber olur. Herkes adalet peşindeyken Memo ve kızı Ova’nın tek isteği birbirlerine kavuşmaktır. Memo suçsuzdur ve şimdi yaşamına geri dönebilmesi için bir mucizeye ihtiyacı vardır.', 8.252, '2019-10-10', 8.6152, 1782681156256, 1782681156256, 0, NULL, 0),
(3, 665733, 0, -1, '[18]', 'Kuru Otlar Üstüne', '/64tHqMoTc9RZKvEcBMAebdUB1R1.jpg', '/y2fxmO7IUV9YXvoUhFppwGcUTt.jpg', 'Genç bir öğretmen olan Samet, Doğu Anadolu\'da zorunlu görevini yapmaktadır. Onun en büyük hayali, zorunlu hizmetini tamamlamasının ardından İstanbul\'a tayin olmaktır. Ancak onun hayatı, meslektaşı Kenan ile bir kız öğrenci tarafından asılsız olarak tacizle suçlanmasıyla altüst olur. Kendisini bir anda büyük bir sıkıntının içinde bulan Samet için işler, kendisine yardımcı olabilecek meslektaşı Nuray ile tanışmasıyla değişir.', 7.679, '2023-07-12', 1.0853, 1782681103524, 1782681103524, 0, NULL, 0),
(3, 785534, 0, -1, '[18]', 'Kağıttan Hayatlar', '/22iaAAr3LZucqLZJ5M8w52gwNiR.jpg', '/ctckqAvz9aTZDtfXLmDUdMflesU.jpg', 'Kağıt toplayarak geçinen ve sağlığı giderek kötüleşen Mehmet terk edilmiş bir çocuk bulur. Birden hayatına giren küçük Ali, onu kendi çocukluğuyla yüzleştirecektir.', 7.965, '2021-03-12', 1.6, 1782681097228, 1782681097228, 0, NULL, 0),
(3, 920394, 0, -1, '[18,10402]', 'Babamın Kemanı', '/aDhoeAnOKY8jR6BJbhDYm3y4dT4.jpg', '/ljJaDl3RdcNdSuQVa2ScdNZOF1L.jpg', 'Babasını yitiren bir kız kendisine mesafeli duran keman virtüözü amcasıyla bağ kurmaya çalışır. Onları bir araya getirecek olan ise ortak acıları ve müzik tutkularıdır.', 7.882, '2022-01-21', 0.7617, 1782681117364, 1782681117364, 0, NULL, 0),
(3, 927855, 0, -1, '[10749,35]', 'Aşk Taktikleri', '/9mXoEX9RNsRD1bG8nmJSfhwaM3O.jpg', '/3ZSXRocKLgBL6gM8nBZsbPq9ZUk.jpg', 'Bir reklam yöneticisi ve bir moda tasarımcısı-blog yazarı aşka inanmazlar, bu yüzden diğerinin tepetaklak olmasını sağlamak için alışılmadık taktiklerle iddiaya girerler.', 7.088, '2022-02-11', 1.6517, 1782681094862, 1782681094862, 0, NULL, 0),
(3, 936075, 0, -1, '[10402,18]', 'Michael', '/Awq135QNhuvZ99VyNZgSlnKxFW2.jpg', '/ufSwlnECLoUbBjPrFqEQcWBzHwc.jpg', 'Michael Jackson\'a gerçek hayattaki yeğeni Jaafar Jackson\'ın hayat verdiği filmde, onu tüm zamanların en büyük şovmeni haline getiren en ikonik performansları da dahil olmak üzere Michael\'ın hayatının tüm yönleri gözler önüne seriliyor.', 8.7, '2026-04-24', 346.6964, 1782678160174, 1782678160174, 0, NULL, 0),
(3, 946726, 0, -1, '[18,35,10749]', 'Sen Yaşamaya Bak', '/qsVvFYZ0HqZsXinbPd2f4lo2bPC.jpg', '/mbxPR3VtGXIRIX5jEUfulJd9A0J.jpg', 'Bekâr bir anne olan Melisa hastadır ve çok az ömrü kalmıştır. Bu kısa sürede hem fırtına gibi bir aşk yaşayıp hem de oğlu Can\'ı emanet edebileceği bir adam bulabilecek midir?', 6.6, '2022-03-21', 0.7831, 1782681116685, 1782681116685, 0, NULL, 0),
(3, 1006911, 0, -1, '[10749,35]', 'Sen İnandır', '/e2OVAX58bmTqYG1B4lP802n0YNZ.jpg', '/mKlBeUZvmHUbo4LObp7OvLVkL2G.jpg', 'Film, çocukluktan birbirine aşık olan ama zaman içinde yolları bambaşka yerlere uzanan iki insanın bir kez daha karşılaşmasını konu alıyor. Torunlarının birbirleriyle evlenmesini isteyen iki büyükanne, onlar için sözde tesadüfi karşılaşma planlarlar. Durumdan haberleri olmayan iki genç karşılaştıklarında, çocukluk aşkları yeniden gün yüzüne çıkar, eski defterler açılır ve önlerine çıkan yeni hikâyeye karşı koymazlar.', 6.4, '2023-06-23', 5.6096, 1782681076208, 1782681076208, 0, NULL, 0),
(3, 1044302, 0, -1, '[10749,18]', 'İstanbul İçin Son Çağrı', '/1xDN6XlRHpsr1HUbdm0Q3grDeeC.jpg', '/wEwE7WtkoQSW7ZmlRI8fRz3C0LQ.jpg', 'New York, aşk ve ikinci şanslar hakkında bir hikaye... İstanbul’dan New York’a giderken havaalanında tesadüfen karşılaşan Serin ve Mehmet, New York\'ta heyecan dolu, baştan çıkarıcı unutulmaz bir geceye sürüklenir. Serin ve Mehmet hayatlarının en güzel anlarını birlikte geçirirken ortada tek bir sorun vardır...', 6.273, '2023-11-24', 1.5266, 1782681098593, 1782681098593, 0, NULL, 0),
(3, 1054513, 0, -1, '[35,10749]', 'Özel Ders', '/aKL4CA8BsdDlKFiF0gaLQAYG4rp.jpg', '/uZtYhcnk3WWvUzQkJLqnNywMQpb.jpg', 'Genç bir kadın olan Azra, özel ders adı ile gençlere yaşam ve ilişki koçluğu yapar. Ancak onun hayatı, apartmanlarına yeni gelen komşusu sayesinde bambaşka bir hal alır. Yeni yakışıklı komşusu, Azra\'ya bildiği doğruları unutturur. Ne de olsa terzi kendi söküğünü dikemez.', 6.7, '2022-12-16', 2.746, 1782681086135, 1782681086135, 0, NULL, 0),
(3, 1074262, 0, -1, '[80,18]', 'Kötü Adamın 10 Günü', '/dLnNFHz6sMsfQtuqDsdIAEpFyVL.jpg', '/sil4GzTAvmxFWqsp5FWZcG7adtS.jpg', 'Hayatta sahip olduğu her şeyi kaybettikten sonra artık kötü bir adam olmaya karar veren Sadık, bir köşkte işlenen tuhaf cinayeti çözmeye çalışır. Aksiyon dolu üçlemenin ikinci filmi.', 6.4, '2023-08-18', 1.0267, 1782681112751, 1782681112751, 0, NULL, 0),
(3, 1084244, 0, 2, '[16,10751,35,12]', 'Oyuncak Hikayesi 5', '/4LHyUPK4obqICeCt4rjhpQDOhJt.jpg', '/qjTqY5coNiz6sVtPng40IzltsoN.jpg', 'Bonnie\'nin hediye olarak aldığı bir Lilypad tablete takıntılı hale gelmesiyle birlikte, Buzz, Woody, Jessie ve diğer oyuncaklar için işler iyice karmaşıklaşır; zira artık oyun saatini tehdit eden yepyeni bir tehlikeyle mücadele etmek zorundadırlar.', 7.5, '2026-06-19', 489.721, 1782678167253, 1782678167253, 0, NULL, 0),
(3, 1128568, 0, -1, '[35,10749]', 'Merve Kült', '/8ykNHGS101LDiFrprD37dhGuug.jpg', '/vWRrLnl4mGayFHm80b7CEg6goAE.jpg', 'Moda düşkünü, özgür ruhlu Merve evinden çıkarılma riskiyle karşı karşıya kalınca para bulmak için bir flört uygulaması geliştirir. Ama çekici patronunun başka planları vardır.', 6.2, '2023-06-09', 0.9579, 1782681113417, 1782681113417, 0, NULL, 0),
(3, 1141202, 0, -1, '[10749,35]', 'Aşk Taktikleri 2', '/bswrvLhN2TbpKx4B8JRDcUpRALk.jpg', '/pbsYbxx6BwB0mw9cmosjb5ueWcd.jpg', 'İddia ile başlayan ilişkilerini birbirlerine karşı hissettikleriyle gerçeğe dönüştüren Aslı ile Kerem, evliliğe inanmamaları konusunda hemfikir olduklarını fark ettiklerinde iş inada biner. Aslı, Kerem\'i evlilik konusunda ikna etmeye çalışırken Kerem de onu bu fikirden uzaklaştırmak için harekete geçer.', 6.985, '2023-07-14', 0.9247, 1782681115116, 1782681115116, 0, NULL, 0),
(3, 1169516, 0, 2, '[28,35,12,80]', 'Welcome to the Jungle', '/1JlfUuvvX5xLP2LIDah4JhWUtTx.jpg', '/96chPcURxg5thGyLqxO6otyxHFR.jpg', '', 5.714, '2026-06-25', 1112.1374, 1782678151499, 1782678151499, 0, NULL, 0),
(3, 1248795, 0, -1, '[10749,28,18]', 'Romantik Hırsız', '/hjYb3zdvuedWmTH4tSD9UU3VjkZ.jpg', '/9jRWk8xxPxs1HhyjUcwgh0jtpuI.jpg', 'Peşine düştüğü sanat eseri hırsızının eski sevgilisi olduğunu öğrenen bir Interpol ajanı, onu suçüstü yakalamak için bir plan yapar.', 6.438, '2024-03-13', 1.7117, 1782681093746, 1782681093746, 0, NULL, 0),
(3, 1273221, 0, 0, '[35]', 'Korkunç Bir Film', '/9mia27aPqVkvPtFbHZphG0tXpXY.jpg', '/xWBiXclrRmTggQHMRsIn84YHavs.jpg', 'Maskeli bir saldırganla ilk karşılaşmalarının üzerinden yirmi altı yıl geçtikten sonra, orijinal grubun hayatta kalan üyeleri Shorty Meeks, Ray Wilkins, Cindy Campbell ve Brenda Meeks hayatlarını bir kez daha tehlikede bulurlar. Ghostface olarak da bilinen katil, geçmişteki olayların kaldığı yerden devam ederek, görünüşe göre onları bir kez daha hedef almaktadır.', 5.441, '2026-06-03', 485.6451, 1782995259376, 1782995259376, 0, NULL, 0),
(3, 1301421, 0, 0, '[12,9648,35,10751]', 'Bir Koyun Polisiyesi', '/yqr2EzcCGIkh367I7uD1oO9ePmO.jpg', '/t6O6XWelu27BD0OmIDCCufZZT6d.jpg', 'George Hardy, her gece çok sevdiği koyunlarına anlayamayacaklarını düşünmesine rağmen dedektif romanları okuyan bir çobandır. Ancak gizemli bir olay, çiftlik hayatını alt üst edince koyunlar, dedektif olmaları gerektiğinin farkına varırlar. İpuçlarını takip edip şüphelileri araştırırken koyunların bile suç çözebileceklerini kanıtlarlar.', 7.745, '2026-04-30', 236.4043, 1782995260172, 1782995260172, 0, NULL, 0),
(3, 1339713, 0, -1, '[27,53]', 'Saplantı', '/rjQ0GbYsLX6WDWefPrxGMCqPqx6.jpg', '/5lTZyuBTNOfawsfPT8Q0cIg6qAF.jpg', 'Umutsuz bir romantik, aşık olduğu kadının kalbini kazanmak için gizemli \"Tek Dilek Söğüdü\"nü kırdıktan sonra tam olarak dilediği şeyi elde eder ancak kısa süre sonra bazı arzuların karanlık ve tekinsiz bir bedeli olduğunu keşfeder.', 7.902, '2026-05-15', 487.4195, 1782678157159, 1782678157159, 0, NULL, 0),
