(4, 27, 0, -1, '[18,10402,10749]', '9 Songs', '/91O7z0vo7MiNWd5xD2BoivwbQsb.jpg', '/qU7tNIMpRqkizIObXfkJY3haTqh.jpg', 'Biri İngiliz biri Amerikalı iki sevgilinin 1 sene boyunca yaşadıkları müzik ve cinsellik ile dolu yoğun ilişkileri.', 5.537, '2004-07-16', 30.439, 1782772700268, 1782772700268, 0, NULL, 0),
