(4, 96450, 1, -1, '[18,9648,80]', 'Bayan Scarlet ve Dük', '/9pbxTckwvaTXMABenkcmO1VhQi8.jpg', '/fRkL08tLtjMKaiDjkdniAS2MXw6.jpg', 'Ünlü bir sihirbazın ortadan kaybolmasının ardından gizemli olay bütün Londra\'nın ilgisini çeker. Dük\'ün davayı üstlenmiş olmasına rağmen Eliza bir gazete tarafından olayı incelemesi için işe alınır.', 7.286, '2020-03-31', 21.1467, 1783286334161, 1783286334161, 0, NULL, 0),
(4, 96608, 1, -1, '[9648,80]', 'The Stranger', '/qKtjZ6f8ip6M7pYiDcVs0QXUAly.jpg', '/97pA0UjBqqgcZFbREQL3U1BQDgX.jpg', 'Bu gerilim dizisinde, eşi hakkında yabancı bir kadından duydukları Adam Price\'ın hayatının alt üst olmasına ve kendini sırlarla örülü bir ağın ortasında bulmasına neden olur.', 7.154, '2020-01-30', 10.4416, 1783286381323, 1783286381323, 0, NULL, 0),
(4, 102359, 1, -1, '[18,35]', 'Мир! Дружба! Жвачка!', '/4aGSzvnULrYUZLUHWkKKk6aaySb.jpg', '/fREIQAjGLckdBQQMbD7Kv9zlJ0z.jpg', '', 8.6, '2020-04-23', 6.9073, 1783286464980, 1783286464980, 0, NULL, 0),
(4, 103413, 0, -1, '[18,10751]', 'Second Best', '/aKnqvAIYLUXm1Lnih0Oc024HbYV.jpg', '/piMXOXK28gdrxoI2Mzul7eu6wcG.jpg', 'The difficult relationship between a british postal officer and his adoptive son.', 6.756, '1994-09-30', 1.4035, 1783286319115, 1783286319115, 0, NULL, 0),
(4, 106840, 1, -1, '[18]', 'แปลรักฉันด้วยใจเธอ', '/37lwoxdqvhQLnWlKQzKpjuiTJVZ.jpg', '/xA8lSeh33ion2x2X6V87egGItAa.jpg', 'Tekneyi yolundan çeviren bir fırtına gibi karmaşık ve dengesiz duygularla derin ilişkilerini yeniden öğrenen iki liseli gencin hikayesi. Yaşadıkları huzurlu Phuket\'e aykırı.', 8.605, '2020-10-22', 6.2927, 1783286445166, 1783286445166, 0, NULL, 0),
(4, 106841, 1, -1, '[18]', '繁花', '/rV1owsdKtXytJ5eFMOOVTze3mrk.jpg', '/3J8HmgR16MKX2iT71mB4EIDdV2x.jpg', '', 8.6, '2023-12-27', 9.6397, 1783286469978, 1783286469978, 0, NULL, 0),
(4, 108978, 1, -1, '[10759,18,80]', 'Reacher', '/31GlRQMiDunO8cl3NxTz34U64rf.jpg', '/voKEhzb4ExOmR0WSvQgLTTqRUEu.jpg', 'Emekli Askerî Polis Subayı Jack Reacher işlemediği bir cinayetten tutuklanınca kendini kirli polisler, karanlık iş adamları ve yozlaşmış siyasetçilerle dolu ölümcül bir komplonun ortasında bulur. Aklından başka bir şeyi olmayan Reacher Margrave, Georgia\'da neler döndüğünü çözmek zorunda kalacaktır.', 8.08, '2022-02-03', 104.5994, 1782998611568, 1782998611568, 0, NULL, 0),
(4, 114703, 1, -1, '[18]', 'นิทานพันดาว', '/4Tghh8Pwazsz4K8MxBKTR6ANq76.jpg', '/gEdrn3vnOzXAdujnoCUyUnJACfc.jpg', '', 8.723, '2021-01-29', 4.3835, 1783286396805, 1783286396805, 0, NULL, 0),
(4, 117067, 1, -1, '[10759,80,18]', 'KinnPorsche', '/mZTfgB9Wi1dtHa5gQAYvbPH15YO.jpg', '/wTgDY1izbDCbdgsNS1ujLk7lepG.jpg', 'Porsche, kardeşi ve amcası ile yaşar. Bir barda çalışır, barmenlik işinde çok iyidir. Amcası tefeciden bırç para almış ve bu nedenle de başı sık sık belaya girmiştir. Amcası başını yine derde sokmuş ve tefeci borucun ödenmesi için gün vermiştir. Porsche bu borcu ödeyemeyecektir. Amcası ile de arası açılacaktır. Kardeşini okutmak ve iyi bir yaşamı olmasını sağlamalıdır. Tam bu sırada barda çalıştığı bir akşam  yaşamın değiştirecek Kinn ile tanışacaktır.', 8.682, '2022-04-02', 17.5114, 1783285576770, 1783285576770, 0, NULL, 0),
(4, 117376, 1, -1, '[10759,35,18,80]', 'Vincenzo', '/mWYW3xNeV2IM06aUl2xMUdLicpa.jpg', '/sf7NCqyVUNoyjYuwW5oJke1T1lH.jpg', '\"Vincenzo\", örgütü içindeki bir çatışma nedeniyle Kore\'ye geri dönen İtalyan avukat Vincenzo Cassano\'nun hikayesini anlatacak. Korece adı Park Joo-Hyung olan Vincenzo Cassano, İtalya’da mafyalara danışmalık yapan bir avukattır. Ancak, mafya grupları arasında bir savaş başlayınca Kore’ye geri döner. Burada, sosyal adaleti kendi yoluyla sağlamaya çalışır. Bu süreçte, aldığı davaları kazanmak için her şeyi yapan Avukat Hong Cha-Young\'a âşık olur. Kötü adamların kullandığı yöntemleri kullanarak adaleti birlikte gerçekleştirirler.', 8.5, '2021-02-20', 22.9309, 1783285566824, 1783285566824, 0, NULL, 0),
(4, 119464, 1, -1, '[18]', '나빌레라', '/8XNj2fN7TwSazpRfvE27VJA65SJ.jpg', '/ylS5KdDgb8s4Y7P3sDifrizvmA4.jpg', 'Hayallerinin peşinden koşan 70 yaşındaki bir adam ve 23 yaşındaki yetenekli bir genç, balet olma yolculuğunda birbirlerine yardım ederek zorlukları aşar.', 8.6, '2021-03-22', 5.254, 1783286459430, 1783286459430, 0, NULL, 0),
(4, 122019, 0, -1, '[18,14]', 'Macario', '/xX9JGtsnXQAR7e1fWkr7zBuQUHN.jpg', '/6SKhqqAPrJyPz9Cx1N1jaOBqV0a.jpg', '', 8.674, '1960-06-09', 1.3885, 1783285516313, 1783285516313, 0, NULL, 0);
INSERT INTO `ratings` (`user_id`, `movie_id`, `is_tv`, `rating`, `genre_ids`, `title`, `poster_path`, `backdrop_path`, `overview`, `vote_average`, `release_date`, `popularity`, `created_at`, `updated_at`, `deleted`, `comment`, `is_spoiler`) VALUES
(4, 122917, 0, 3, '[28,12,14]', 'Hobbit: Beş Ordunun Savaşı', '/ncIV890nmkYCGImfp0oQflBvU5d.jpg', '/3UbaCMmqOd7mca4Y5DOzY2ZVTyX.jpg', 'Bilbo Baggins, korkunç ejderha Smaug\'dan Cüce Krallığı\'nı geri almak için çıkılan yolculuğa katılıyor. Aniden çıkagelen Gandalf tarafından bir grup Cüce\'ye katılması istenir. Her çeşit yaratıkların bulunduğu yaban ellerde bu cüce grubu ile kendini bir maceranın ortasında bulur. Erebor\'a vardıktan ve Smaug ile karşılaştıktan sonra Beş Ordu güçlerini birleştirerek, Orta Dünya\'nın kaderini belirleyecek bir savaşa başlar.', 7.337, '2014-12-10', 19.6551, 1783254142638, 1783254142638, 0, NULL, 0),
(4, 124364, 1, -1, '[9648,18,10765]', 'FROM', '/pRtJagIxpfODzzb0T0NAvZSzErC.jpg', '/m7eiSGHFzr584zFmetGqkqaU6BN.jpg', 'Amerika Birleşik Devletleri\'nin ortasındaki kabus gibi bir şehir, içine giren herkesi tuzağa düşürür. Kasaba sakinleri, normallik duygusunu sürdürmek ve bir çıkış yolu aramak için savaşırken, güneş battığında ortaya çıkan korkunç yaratıklar da dahil olmak üzere, çevredeki ormandan gelen tehditlere karşı da hayatta kalmak için çabalar.', 8.505, '2022-02-20', 765.3461, 1782998790940, 1782998790940, 0, NULL, 0),
(4, 125988, 1, -1, '[10765,18]', 'Silo', '/gMYZZvnkVNTqSVnVCphWbPXwWwb.jpg', '/uTWhbLc7Bj4qNSdW3ZvZKL8cOHv.jpg', 'Mahvolmuş ve zehirli bir gelecekte, binlerce kişi yeraltının derinliklerindeki dev bir siloda yaşamaktadır. Silo\'nun şerifi temel bir kuralı çiğnedikten ve sakinler gizemli bir şekilde ölmeye başladıktan sonra mühendis Juliette, Silo hakkındaki şok edici sırları ve gerçeği ortaya çıkarmaya başlar.', 8.2, '2023-05-04', 202.6294, 1783286310168, 1783286310168, 0, NULL, 0),
(4, 126485, 1, -1, '[9648,18,10759]', 'Moving', '/b9MhD5syJ7TbYSeje4wB4oyTzc7.jpg', '/29jWaRhKtey1efp5G7Fu97NAmzz.jpg', 'Bu doğaüstü aksiyon dizisinde süper güçleriyle saklanarak yaşayan çocuklar, geçmişin acı sırlarıyla yaşayan anne babalarıyla birlikte, çok büyük tehlikelerle karşı karşıya kalıyor.', 8.505, '2023-08-09', 24.1403, 1783285579186, 1783285579186, 0, NULL, 0),
(4, 127373, 0, -1, '[18]', 'Arada Kalan', '/d0UZFM7J65D9cnWK0RurFRwQbT.jpg', '/kk1MMdWF9Z4vBMM0ebBjD7G5zFf.jpg', 'Altı yaşındaki Maisie, rock yıldızı annesi Susanna ile karizmatik ancak ilgisiz sanat simsarı babası Beale´in tatsız boşanmasının sarsıntılarıyla boğuşmaktadır. Maisie’nin hayatına, boşanmanın ardından anne ve babasının yeni eşleri de girer. Ancak küçük kız, eşlerinin bencilliğini fark edip birbirlerine âşık olan üvey ebeveyniyle yakınlaşınca durum iyice çetrefilleşir.', 7.1, '2013-05-02', 2.0093, 1783286358127, 1783286358127, 0, NULL, 0),
(4, 132306, 1, -1, '[9648,18,80]', 'Ridley', '/gdvihv6BhxYDWquoQbZctlVSBwS.jpg', '/fDNtuXUbx7w4yz4X63YZ4oVzSVi.jpg', 'Retired Detective Inspector Alex Ridley is lured back into service as a consultant detective when his former protégée, Carol Farman, needs help cracking a complex murder case.', 6.147, '2022-08-28', 8.2256, 1783286355577, 1783286355577, 0, NULL, 0),
(4, 133490, 1, -1, '[10751,18,80]', 'Yargı', '/lPniIaLkepX4RKaUmvAJmoR1RCv.jpg', '/fCwZOi3cTEOi2UkhjJNbFQnl4IW.jpg', 'Ceylin gözü kara ve kurallar söz konusu olduğunda sınır tanımayan bir avukattır. Bir müvekkiliyle ilgili yine illegal yoldan bilgi alabilmek için savcı Ilgaz’ın karşısına çıkar. Ancak Ilgaz’ın, Ceylin’in tam aksine, mesleki etik konusunda katı kuralları vardır, bu yüzden de kariyerinde çok başarılı ve sözü dinlenen bir savcıdır.  Ilgaz kardeşi Çınar’ın katil olmakla suçlandığı bir cinayet vakasıyla karşılaşınca; ilk defa kendi kurallarını yıkar. Ceylin’den kardeşini savunmasını ister. Bu noktadan sonra işler ikisinin de tahmin edemeyeceği bir yola girer. Ilgaz ve Ceylin; Çınar’ın aklanması için çalışırken, kendilerini ikisinin de ailelerine kadar uzanan bir gizem yumağının içinde bulacaklardır.', 8.6, '2021-09-19', 28.4792, 1782934566529, 1782934566529, 0, NULL, 0),
(4, 133813, 1, -1, '[9648,18,80]', 'Death and Other Details', '/2DEa0Bz3j9ZhPRdBmNyco38OR6p.jpg', '/8Xh6YJr2VS66EiifbtDYV3ZgoVT.jpg', 'Imogene Scott kendini yanlış yerde/zamanda bulur ve bir cinayet gizeminin şüphelisi haline gelir.', 6.542, '2024-01-16', 9.9203, 1783286352394, 1783286352394, 0, NULL, 0),
(4, 134297, 1, -1, '[16,10751,35,10765]', 'Olaf Presents', '/bO3KHoznXTiptzW9Ur5FmqWvYKc.jpg', '/676dcwmQgxCQMqf1lSpPf1g8X8n.jpg', 'Frozen’s beloved snowman retelling several classic Disney tales as only he can.', 7.169, '2021-11-12', 4.8812, 1783286332595, 1783286332595, 0, NULL, 0),
(4, 135157, 1, -1, '[18,10765,10759,9648]', 'Alchemy of Souls', '/pGs6UA4rPUZEokDyTwAGdRvwrAD.jpg', '/nBZyWSGAUEzCH7Mna0zUNTpBQlQ.jpg', 'Yaşamını kör bir kadının bedeninde sürdüren bir büyücü, kaderini değiştirmek için ondan yardım isteyen, prestijli bir aileye mensup bir adamla karşılaşır.', 8.6, '2022-06-18', 34.5478, 1783285560125, 1783285560125, 0, NULL, 0),
(4, 136228, 1, -1, '[18,10766,35,10751]', 'Pa Quererte', '/yVq9cbegB2Ft9o8VDMiHcc0BnkV.jpg', '/va8cLePI0khniYu6luIHcdXrzMg.jpg', '', 9.186, '2020-01-07', 29.7941, 1783286304102, 1783286304102, 0, NULL, 0),
(4, 136315, 1, -1, '[18,35]', 'The Bear', '/eKfVzzEazSIjJMrw9ADa2x8ksLz.jpg', '/aJtG4txtmiRHwAAqENQHZvBs6kY.jpg', 'Gastronomi dünyasından genç bir şef olan Carmen \"Carmy\" Berzatto, yürek burkan bir ölümün ardından ailesinin sandviç dükkanını işletmek için Chicago\'ya dönmek zorunda kalır. Kendi dünyasından uzakta olan Carmy, bir trajedinin sonuçlarına katlanırken küçük bir işletmenin, inatçı bir personelin ve gergin aile ilişkilerinin ezici sorumluluklarıyla uğraşmak zorundadır.', 8.139, '2022-06-23', 118.8106, 1782772670204, 1782772670204, 0, NULL, 0),
(4, 137127, 1, -1, '[80,18,9648]', 'Dalgliesh', '/8pqCanIwJFehhZdP00gXE0qc9xc.jpg', '/n7peMGJTGdchAZoQsYCyzMsxe5k.jpg', '\"Dalgliesh\" dizisi, Phyllis Dorothy James\'in Müfettiş Adam Dalgliesh\'i anlatan ve en çok satan romanlarına dayanmaktadır.\n\nDizi 1970\'lerin İngiltere\'sinde geçmekte ve sıradışı cinayetleri çözerken ve gömülü sırları açığa çıkarırken vakaları kariyeri günümüze kadar takip eden esrarengiz dedektifin bakış açısından anlatmaktadır.', 6.8, '2021-11-04', 12.1881, 1783286290488, 1783286290488, 0, NULL, 0),
